import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { GoogleOAuthProvider } from '@react-oauth/google';
import { AuthProvider, useAuth } from './context/AuthContext';
// Forced HMR Recompilation trigger

import Sidebar from './components/layout/Sidebar';
import StudentSidebar from './components/layout/StudentSidebar';
import CaretakerSidebar from './components/layout/CaretakerSidebar';
import WardenSidebar from './components/layout/WardenSidebar';

import LoginPage from './pages/LoginPage';

// ── ADMIN MODULE PAGES ───────────────────────────────────────
// Reports & Analytics
import DashboardPage from './pages/admin/reports/DashboardPage';
import AdminAttendanceReportsPage from './pages/admin/reports/AdminAttendanceReportsPage';
// User Management
import AdminUsersPage from './pages/admin/users/UsersPage';
import StudentsPage from './pages/admin/users/StudentsPage';
import FloorWardenPage from './pages/admin/users/FloorWardenPage';
import AdminWardenDetailPage from './pages/admin/users/AdminWardenDetailPage';
// Hostel & Room Management
import AdminHostelsPage from './pages/admin/hostels/AdminHostelsPage';
import RoomsPage from './pages/admin/hostels/RoomsPage';
import AllocationsPage from './pages/admin/hostels/AllocationsPage';
import MessMenuPage from './pages/admin/hostels/MessMenuPage';
import VisitorManagementPage from './pages/admin/hostels/VisitorManagementPage';
// Requests & Applications
import AdminApplicationReview from './pages/admin/requests/AdminApplicationReview';
import AdminLeaveApprovals from './pages/admin/requests/AdminLeaveApprovals';
// Complaints Management
import ComplaintsPage from './pages/admin/complaints/ComplaintsPage';
import NoticesPage from './pages/admin/complaints/NoticesPage';
import AdminMessagesPage from './pages/admin/complaints/AdminMessagesPage';

// ── WARDEN PAGES ──────────────────────────────────────────────
import WardenLeaveApprovals from './pages/warden/WardenLeaveApprovalsPortal';
import WardenDashboard from './pages/warden/WardenDashboardPortal';
import WardenStudents from './pages/warden/WardenStudentsPortal';
import WardenComplaints from './pages/warden/WardenComplaintsPortal';
import WardenApplicationReview from './pages/warden/WardenApplicationReview';
import WardenRequestManagement from './pages/warden/WardenRequestManagement';
import WardenAttendance from './pages/warden/WardenAttendance';
import WardenMessagesPage from './pages/warden/WardenMessagesPage';

// ── STUDENT PAGES ──────────────────────────────────────────────
import StudentDashboard from './pages/student/StudentDashboardPortal';
import StudentProfile from './pages/student/StudentProfile';
import StudentLeaveRequest from './pages/student/StudentLeaveRequestPortal';
import StudentComplaints from './pages/student/StudentComplaints';
import StudentNotices from './pages/student/StudentNoticesPortal';
import StudentHostelApplication from './pages/student/StudentHostelApplication';
import StudentRequests from './pages/student/StudentRequests';
import StudentAttendance from './pages/student/StudentAttendance';
import StudentStaffDirectory from './pages/student/StudentStaffDirectory';
import StudentVisitorRequests from './pages/student/StudentVisitorRequests';
import StudentMyRoomPage from './pages/student/StudentMyRoom';

// ── CARETAKER PAGES ────────────────────────────────────────────
import CaretakerDashboard from './pages/caretaker/CaretakerDashboardPortal';
import CaretakerComplaints from './pages/caretaker/CaretakerComplaintsPortal';

import { Spinner } from './components/ui';

function getHomePath({ user, isAdmin, isCaretaker, isWarden, isStudent }) {
  if (!user) return '/login';
  if (isAdmin) return '/';
  if (isCaretaker) return '/caretaker';
  if (isWarden) return '/warden';
  if (isStudent) return '/student';
  return '/login';
}

function ProtectedRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-brand-bg">
      <Spinner size="lg" className="text-brand-primary" />
    </div>
  );
  return user ? children : <Navigate to="/login" replace />;
}

function AdminRoute({ children }) {
  const auth = useAuth();
  if (!auth.isAdmin) return <Navigate to={getHomePath(auth)} replace />;
  return children;
}

function CaretakerRoute({ children }) {
  const auth = useAuth();
  if (!auth.isCaretaker && !auth.isAdmin) return <Navigate to={getHomePath(auth)} replace />;
  return children;
}

function WardenRoute({ children }) {
  const auth = useAuth();
  if (!auth.isWarden && !auth.isAdmin) return <Navigate to={getHomePath(auth)} replace />;
  return children;
}

function StudentRoute({ children }) {
  const auth = useAuth();
  if (!auth.isStudent) return <Navigate to={getHomePath(auth)} replace />;
  return children;
}

function AppRoutes() {
  const auth = useAuth();
  const { user } = auth;

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to={getHomePath(auth)} replace /> : <LoginPage />} />

      {/* Admin Routes */}
      <Route path="/*" element={
        <ProtectedRoute>
          <AdminRoute>
            <Sidebar>
              <Routes>
                {/* Reports & Analytics */}
                <Route path="/"            element={<DashboardPage />} />
                <Route path="/attendance-reports" element={<AdminAttendanceReportsPage />} />

                {/* User Management */}
                <Route path="/users"       element={<AdminUsersPage />} />
                <Route path="/students"    element={<StudentsPage />} />
                <Route path="/floor-wardens" element={<FloorWardenPage />} />
                <Route path="/wardens/:id" element={<AdminWardenDetailPage />} />

                {/* Hostel & Room Management */}
                <Route path="/hostels"     element={<AdminHostelsPage />} />
                <Route path="/rooms"       element={<RoomsPage />} />
                <Route path="/allocations" element={<AllocationsPage />} />
                <Route path="/mess-menu"   element={<MessMenuPage />} />
                <Route path="/visitors"    element={<VisitorManagementPage />} />

                {/* Requests & Applications */}
                <Route path="/applications" element={<AdminApplicationReview />} />
                <Route path="/outpasses"   element={<AdminLeaveApprovals />} />

                {/* Complaints Management */}
                <Route path="/complaints"  element={<ComplaintsPage />} />
                <Route path="/notices"     element={<NoticesPage />} />
                <Route path="/messages"    element={<AdminMessagesPage />} />

                <Route path="*"            element={<Navigate to="/" replace />} />
              </Routes>
            </Sidebar>
          </AdminRoute>
        </ProtectedRoute>
      } />

      {/* Caretaker Routes */}
      <Route path="/caretaker/*" element={
        <ProtectedRoute>
          <CaretakerRoute>
            <CaretakerSidebar>
              <Routes>
                <Route path="/"           element={<CaretakerDashboard />} />
                <Route path="/complaints" element={<CaretakerComplaints />} />
                <Route path="*"           element={<Navigate to="/caretaker" replace />} />
              </Routes>
            </CaretakerSidebar>
          </CaretakerRoute>
        </ProtectedRoute>
      } />

      {/* Warden Routes */}
      <Route path="/warden/*" element={
        <ProtectedRoute>
          <WardenRoute>
            <WardenSidebar>
              <Routes>
                <Route path="/"            element={<WardenDashboard />} />
                <Route path="/students"    element={<WardenStudents />} />
                <Route path="/applications" element={<WardenApplicationReview />} />
                <Route path="/requests"    element={<WardenRequestManagement />} />
                <Route path="/attendance"  element={<WardenAttendance />} />
                <Route path="/outpasses"   element={<WardenLeaveApprovals />} />
                <Route path="/mess-menu"   element={<MessMenuPage />} />
                <Route path="/visitors"    element={<VisitorManagementPage />} />
                <Route path="/complaints"  element={<WardenComplaints />} />
                <Route path="/messages"    element={<WardenMessagesPage />} />
                <Route path="*"            element={<Navigate to="/warden" replace />} />
              </Routes>
            </WardenSidebar>
          </WardenRoute>
        </ProtectedRoute>
      } />

      {/* Student Routes */}
      <Route path="/student/*" element={
        <ProtectedRoute>
          <StudentRoute>
            <StudentSidebar>
              <Routes>
                <Route path="/"            element={<StudentDashboard />} />
                <Route path="/profile"     element={<StudentProfile />} />
                <Route path="/applications" element={<StudentHostelApplication />} />
                <Route path="/requests"    element={<StudentRequests />} />
                <Route path="/visitors"    element={<StudentVisitorRequests />} />
                <Route path="/attendance"  element={<StudentAttendance />} />
                <Route path="/outpass"     element={<StudentLeaveRequest />} />
                <Route path="/mess-menu"   element={<MessMenuPage />} />
                <Route path="/complaints"  element={<StudentComplaints />} />
                <Route path="/notices"     element={<StudentNotices />} />
                <Route path="/staff-directory" element={<StudentStaffDirectory />} />
                <Route path="/my-room"       element={<StudentMyRoomPage />} />
                <Route path="*"            element={<Navigate to="/student" replace />} />
              </Routes>
            </StudentSidebar>
          </StudentRoute>
        </ProtectedRoute>
      } />
    </Routes>
  );
}

const GOOGLE_CLIENT_ID = '181603728534-78tjb4gbu8p6olk8mtpqj2h2guls23vv.apps.googleusercontent.com';

export default function App() {
  return (
    <GoogleOAuthProvider clientId={GOOGLE_CLIENT_ID}>
      <AuthProvider>
        <BrowserRouter future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
          <AppRoutes />
          <Toaster
            position="top-right"
            toastOptions={{
              style: { borderRadius: '12px', fontSize: '13px', fontFamily: 'Manrope, Segoe UI, sans-serif' },
              success: { iconTheme: { primary: '#7D53F6', secondary: '#fff' } },
            }}
          />
        </BrowserRouter>
      </AuthProvider>
    </GoogleOAuthProvider>
  );
}

import React from 'react';

const SIZE_CLASSES = {
  sm: 'h-12 w-12 rounded-[18px] text-base',
  md: 'h-14 w-14 rounded-[20px] text-lg',
  lg: 'h-24 w-24 rounded-[34px] text-[2rem]',
};

export default function LogoMark({ size = 'md', className = '' }) {
  return (
    <div
      className={`relative flex items-center justify-center overflow-hidden border border-[#D6DBEE] bg-white text-white shadow-sm ${SIZE_CLASSES[size] || SIZE_CLASSES.md} ${className}`}
    >
      <div className="absolute inset-[1px] rounded-[inherit] border border-white/80" />
      <svg className="relative z-10 h-[68%] w-[68%]" viewBox="0 0 64 64" fill="none" aria-hidden="true">
        <path
          d="M10 42.5c0-13.4 9.8-23 22-23s22 9.6 22 23h-9.6c0-8.2-5.4-14.1-12.4-14.1S19.6 34.3 19.6 42.5H10Z"
          fill="#2F3396"
        />
        <path d="M8.8 42.5h13.1v5.2H6.5l2.3-5.2Z" fill="#2F3396" />
        <path d="M42.1 42.5h13.1l2.3 5.2H42.1v-5.2Z" fill="#2F3396" />
        <path d="M32 17.2 44 23.9 32 30.7 20 23.9 32 17.2Z" fill="#C3A73A" />
        <path d="M20 23.9 32 30.7V45L20 38.3V23.9Z" fill="#B29322" />
        <path d="M44 23.9 32 30.7V45l12-6.7V23.9Z" fill="#D0B95B" />
        <path d="M27.1 21.7 32 19l4.9 2.7-4.9 2.8-4.9-2.8Z" fill="#F5E7A4" />
        <path d="M24.8 29.3h4.9c1 0 1.8.8 1.8 1.8v1.4c0 1-.8 1.8-1.8 1.8h-4.9c-1 0-1.8-.8-1.8-1.8v-1.4c0-1 .8-1.8 1.8-1.8Z" fill="#FFF7D1" />
        <path d="M34.3 31.1c0-1 .8-1.8 1.8-1.8H41c1 0 1.8.8 1.8 1.8v1.4c0 1-.8 1.8-1.8 1.8h-4.9c-1 0-1.8-.8-1.8-1.8v-1.4Z" fill="#FFF7D1" />
        <path d="M32 14.7 39.3 18.8l-2.6 1.5-4.7-2.7-4.7 2.7-2.6-1.5 7.3-4.1Z" fill="#C3A73A" />
      </svg>
    </div>
  );
}

import React, { useState } from 'react';
import { NavLink, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, Home, FileText, Wrench, LogOut, Menu, X } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

const NAV_GROUPS = [
  {
    title: 'Overview',
    items: [
      { to: '/caretaker', label: 'Dashboard', icon: Home, end: true },
    ]
  },
  {
    title: 'Operations',
    items: [
      { to: '/caretaker/complaints', label: 'Complaints', icon: FileText },
    ]
  }
];

function NavItem({ to, label, icon: Icon, onClick, end = false }) {
  return (
    <NavLink
      to={to}
      end={end}
      onClick={onClick}
      className={({ isActive }) =>
        `flex items-center justify-between px-6 py-2.5 text-[13px] font-medium transition-all duration-200 ${isActive
          ? 'bg-brand-primary/10 text-brand-primary border-l-4 border-brand-primary'
          : 'text-gray-600 hover:bg-gray-50 border-l-4 border-transparent'
        }`
      }
    >
      <div className="flex items-center gap-3">
        <Icon className="h-4 w-4" />
        <span>{label}</span>
      </div>
      <ChevronRight className="h-4 w-4 text-gray-400" />
    </NavLink>
  );
}

export default function CaretakerSidebar({ children }) {
  const contentZoom = 0.72;
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const allItems = NAV_GROUPS.flatMap(g => g.items);
  const activeItem = allItems.find(item => (item.to === '/caretaker' ? location.pathname === '/caretaker' : location.pathname.startsWith(item.to)));
  const pageTitle = activeItem?.label || 'Caretaker Dashboard';
  const initials = user?.name?.charAt(0)?.toUpperCase() || 'C';

  return (
    <div className="min-h-screen bg-brand-surface font-sans">
      <aside className="fixed inset-y-0 left-0 z-40 hidden w-[272px] flex-col border-r border-white/70 bg-white/85 shadow-[0_24px_60px_rgba(145,158,171,0.16)] backdrop-blur-xl lg:flex">
        <div className="border-b border-brand-border/70 px-6 py-6">
          <div className="flex items-center gap-2">
            <img src="/bit-hostel-logo.png" alt="BIT Logo" className="h-12 w-12 object-contain drop-shadow-sm" />
            <div className="leading-tight">
              <div className="text-[14px] font-bold text-gray-900">Caretaker</div>
              <div className="text-[12px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Operations Portal</div>
            </div>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto py-5 space-y-4 custom-scrollbar">
          {NAV_GROUPS.map((group, idx) => (
            <div key={idx}>
              <div className="px-6 mb-2 text-[11px] font-bold uppercase tracking-wider text-brand-muted/70">
                {group.title}
              </div>
              <div className="space-y-0.5">
                {group.items.map(item => (
                  <NavItem key={item.to + item.label} {...item} />
                ))}
              </div>
            </div>
          ))}
        </nav>

        <div className="p-4 border-t border-brand-border/70">
          <button
            type="button"
            onClick={handleLogout}
            className="flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-[13px] font-medium text-gray-600 transition-colors hover:bg-orange-50 hover:text-orange-600"
          >
            <LogOut className="h-4 w-4" />
            <span>Logout</span>
          </button>
        </div>
      </aside>

      <div className="lg:pl-[272px] flex flex-col min-h-screen">
        <header className="sticky top-0 z-30 px-6 pb-2 pt-4 lg:px-8">
          <div className="flex w-full items-center justify-between rounded-[28px] border border-white/70 bg-white/80 px-6 py-4 shadow-[0_18px_44px_rgba(145,158,171,0.12)] backdrop-blur-xl">
            <div className="flex items-center gap-3">
              <button
                type="button"
                onClick={() => setMobileOpen(open => !open)}
                className="rounded-xl bg-orange-50 p-2 text-orange-600 lg:hidden"
              >
                <Menu className="h-5 w-5" />
              </button>
              <div className="flex items-center gap-2">
                <div className="flex h-10 w-10 items-center justify-center rounded-2xl bg-orange-50 text-orange-600">
                  <Wrench className="h-4 w-4" />
                </div>
                <div>
                  <div className="text-[11px] uppercase tracking-[0.18em] text-brand-muted">Caretaker Workspace</div>
                  <span className="font-semibold text-gray-800">{pageTitle}</span>
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden rounded-[18px] border border-orange-100 bg-orange-50 px-4 py-2 sm:block">
                <div className="text-[11px] uppercase tracking-[0.16em] text-brand-muted">Caretaker</div>
                <div className="text-sm font-semibold text-gray-900">{user?.name || 'Caretaker'}</div>
              </div>
              <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-gradient-to-br from-orange-400 to-orange-600 text-sm font-bold text-white shadow-md">
                {initials}
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 px-6 lg:px-8 py-6">
          <div className="max-w-7xl mx-auto" style={{ zoom: contentZoom }}>
            {children}
          </div>
        </main>
      </div>

      <AnimatePresence>
        {mobileOpen ? (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setMobileOpen(false)}
              className="fixed inset-0 z-40 bg-black/50 lg:hidden"
            />
            <motion.aside
              initial={{ x: -250 }}
              animate={{ x: 0 }}
              exit={{ x: -250 }}
              className="fixed inset-y-0 left-0 z-50 w-[272px] flex-col bg-white shadow-lg lg:hidden"
            >
              <div className="flex h-[80px] items-center justify-between px-6 border-b border-brand-border/70">
                <div className="flex items-center gap-2">
                  <img src="/bit-hostel-logo.png" alt="BIT Logo" className="h-10 w-10 object-contain drop-shadow-sm" />
                  <div className="leading-tight">
                    <div className="text-[14px] font-bold text-gray-900">Caretaker</div>
                    <div className="text-[12px] font-semibold text-gray-600">Portal</div>
                  </div>
                </div>
                <button onClick={() => setMobileOpen(false)}>
                  <X className="h-5 w-5 text-gray-600" />
                </button>
              </div>

              <nav className="flex-1 overflow-y-auto py-5 space-y-4">
                {NAV_GROUPS.map((group, idx) => (
                  <div key={idx}>
                    <div className="px-6 mb-2 text-[11px] font-bold uppercase tracking-wider text-brand-muted/70">
                      {group.title}
                    </div>
                    <div className="space-y-0.5">
                      {group.items.map(item => (
                        <NavItem
                          key={item.to + item.label}
                          {...item}
                          onClick={() => setMobileOpen(false)}
                        />
                      ))}
                    </div>
                  </div>
                ))}
              </nav>

              <div className="p-4 border-t border-brand-border/70">
                <button
                  type="button"
                  onClick={handleLogout}
                  className="flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-[13px] font-medium text-gray-600 transition-colors hover:bg-orange-50 hover:text-orange-600"
                >
                  <LogOut className="h-4 w-4" />
                  <span>Logout</span>
                </button>
              </div>
            </motion.aside>
          </>
        ) : null}
      </AnimatePresence>
    </div>
  );
}

import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { ChevronRight, Home, Users, CheckSquare, List, Calendar, FileText, Settings, LogOut, Menu, X, Building2, MessageSquare, CreditCard, ClipboardCheck } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

const NAV_GROUPS = [
  {
    title: 'Reports & Analytics',
    items: [
      { to: '/', label: 'Admin Dashboard', icon: Home, end: true },
      { to: '/attendance-reports', label: 'Attendance Reports', icon: ClipboardCheck },
    ]
  },
  {
    title: 'User Management',
    items: [
      { to: '/users', label: 'Admins & Staff', icon: Users },
      { to: '/students', label: 'All Students', icon: Users },
      { to: '/floor-wardens', label: 'Floor Wardens', icon: Users },
    ]
  },
  {
    title: 'Hostel & Room Management',
    items: [
      { to: '/hostels', label: 'Hostels', icon: Building2 },
      { to: '/rooms', label: 'Rooms Listing', icon: List },
      { to: '/allocations', label: 'Room Allocation', icon: CheckSquare },
      { to: '/mess-menu', label: 'Mess Menu', icon: List },
      { to: '/visitors', label: 'Visitors', icon: Users },
    ]
  },
  {
    title: 'Requests & Applications',
    items: [
      { to: '/applications', label: 'Hostel Applications', icon: Building2 },
      { to: '/outpasses', label: 'Leave / Outpasses', icon: CheckSquare },
    ]
  },
  {
    title: 'Complaints Management',
    items: [
      { to: '/complaints', label: 'Complaints', icon: FileText },
      { to: '/notices', label: 'Announcements', icon: Calendar },
      { to: '/messages', label: 'Warden Messages', icon: MessageSquare },
    ]
  }
];

function NavItem({ to, label, icon: Icon, onClick, end = false }) {
  return (
    <NavLink
      to={to}
      end={end}
      onClick={onClick}
      className={({ isActive }) =>
        `flex items-center justify-between px-6 py-2.5 text-[13px] font-medium transition-all duration-200 ${isActive
          ? 'bg-brand-primary/10 text-brand-primary border-l-4 border-brand-primary'
          : 'text-gray-600 hover:bg-gray-50 border-l-4 border-transparent'
        }`
      }
    >
      <div className="flex items-center gap-3">
        <Icon className="h-4 w-4" />
        <span>{label}</span>
      </div>
      <ChevronRight className="h-4 w-4 text-gray-400 opacity-50" />
    </NavLink>
  );
}

export default function Sidebar({ children }) {
  const contentZoom = 0.72;
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const pageTitle = 'Administrator Dashboard';
  const initials = user?.name?.charAt(0)?.toUpperCase() || 'A';

  return (
    <div className="min-h-screen bg-brand-surface font-sans page-shell">
      <aside className="fixed inset-y-0 left-0 z-40 hidden w-[272px] flex-col border-r border-white/70 bg-white/85 shadow-[0_24px_60px_rgba(145,158,171,0.16)] backdrop-blur-xl lg:flex">
        <div className="border-b border-brand-border/70 px-6 py-6">
          <div className="flex items-center gap-3">
            <img src="/bit-hostel-logo.png" alt="BIT Logo" className="h-12 w-12 object-contain drop-shadow-sm" />
            <div className="leading-tight">
              <div className="text-[15px] font-bold text-gray-900">Bannari Amman</div>
              <div className="text-[12px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Admin Portal</div>
            </div>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto py-5 space-y-4 custom-scrollbar">
          {NAV_GROUPS.map((group, idx) => (
            <div key={idx}>
              <div className="px-6 mb-2 text-[11px] font-bold uppercase tracking-wider text-brand-muted/70">
                {group.title}
              </div>
              <div className="space-y-0.5">
                {group.items.map(item => (
                  <NavItem key={item.to + item.label} {...item} />
                ))}
              </div>
            </div>
