}) {
  const accents = {
    primary: {
      glow: 'bg-brand-primary/12',
      soft: 'bg-[#f4f1ff]',
      text: 'text-brand-primary',
      ring: 'border-[#ece8ff]',
      icon: 'bg-brand-primary/12 text-brand-primary',
    },
    orange: {
      glow: 'bg-[#CDBDF1]/30',
      soft: 'bg-[#CDBDF1]/20',
      text: 'text-[#2F3396]',
      ring: 'border-[#CDBDF1]',
      icon: 'bg-[#CDBDF1]/40 text-[#2F3396]',
    },
    blue: {
      glow: 'bg-sky-500/10',
      soft: 'bg-sky-50',
      text: 'text-sky-600',
      ring: 'border-sky-100',
      icon: 'bg-sky-100 text-sky-600',
    },
  };

  const palette = accents[accent] || accents.primary;

