import React, { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { roomsAPI } from '../../../services/api';
import { Button, Badge, Select, Spinner, PageHeader, SectionCard } from '../../../components/ui';

export default function FloorWardenPage() {
  const [wardens, setWardens] = useState([]);
  const [floorWardens, setFloorWardens] = useState([]);
  const [assignmentLoading, setAssignmentLoading] = useState(true);
  const [assignmentSaving, setAssignmentSaving] = useState(false);
  const [assignmentBlock, setAssignmentBlock] = useState('A');
  const [assignmentFloor, setAssignmentFloor] = useState(1);
  const [wingAssignments, setWingAssignments] = useState({ left: '', right: '' });

  const loadAssignments = useCallback(() => {
    setAssignmentLoading(true);
    Promise.all([
      roomsAPI.getWardens(),
      roomsAPI.getFloorWardens({ block: assignmentBlock, floor: assignmentFloor }),
    ])
      .then(([wardenResponse, assignmentResponse]) => {
        const wardenList = wardenResponse.data.data || [];
        const assignmentList = assignmentResponse.data.data || [];
        setWardens(wardenList);
        setFloorWardens(assignmentList);
        setWingAssignments({
          left: assignmentList.find(item => item.wing === 'left')?.warden_id || '',
          right: assignmentList.find(item => item.wing === 'right')?.warden_id || '',
        });
      })
      .catch(() => toast.error('Failed to load floor wardens.'))
      .finally(() => setAssignmentLoading(false));
  }, [assignmentBlock, assignmentFloor]);

  useEffect(() => {
    loadAssignments();
  }, [loadAssignments]);

  const saveFloorWardens = async () => {
    if (wingAssignments.left && wingAssignments.right && Number(wingAssignments.left) === Number(wingAssignments.right)) {
      toast.error('Left wing and right wing must have different wardens.');
      return;
    }
    setAssignmentSaving(true);
    try {
      await roomsAPI.setFloorWardens({
        block: assignmentBlock,
        floor: assignmentFloor,
        assignments: {
          left: wingAssignments.left || null,
          right: wingAssignments.right || null,
        },
      });
      toast.success('Floor warden assignment updated.');
      loadAssignments();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update floor wardens.');
    } finally {
      setAssignmentSaving(false);
    }
  };

  return (
    <div className="space-y-5 animate-fade-in">
      <PageHeader
        eyebrow="Facilities Management"
        title="Floor Wardens"
        description="Manage separate wardens for the left wing and right wing of a specific block and floor."
      />

      <SectionCard
        title="Floor Warden Assignment"
        description="Assign separate wardens for the left wing and right wing of a specific block and floor."
        action={<Button size="sm" onClick={saveFloorWardens} loading={assignmentSaving}>Save Floor Wardens</Button>}
      >
        <div className="space-y-4">
          <div className="flex flex-wrap gap-3">
            <Select value={assignmentBlock} onChange={e => setAssignmentBlock(e.target.value)}>
              {['A', 'B', 'C', 'D'].map(b => <option key={b} value={b}>Block {b}</option>)}
            </Select>
            <Select value={assignmentFloor} onChange={e => setAssignmentFloor(Number(e.target.value))}>
              {[1, 2, 3, 4, 5].map(f => <option key={f} value={f}>Floor {f}</option>)}
            </Select>
          </div>

          {assignmentLoading ? (
            <div className="flex justify-center py-8"><Spinner /></div>
          ) : (
            <>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Select
                  label="Left Wing Warden"
                  value={wingAssignments.left}
                  onChange={e => setWingAssignments(current => ({ ...current, left: e.target.value }))}
                >
                  <option value="">Select warden</option>
                  {wardens.map(warden => (
                    <option key={warden.id} value={warden.id}>{warden.name} ({warden.email})</option>
                  ))}
                </Select>

                <Select
                  label="Right Wing Warden"
                  value={wingAssignments.right}
                  onChange={e => setWingAssignments(current => ({ ...current, right: e.target.value }))}
                >
                  <option value="">Select warden</option>
                  {wardens.map(warden => (
                    <option key={warden.id} value={warden.id}>{warden.name} ({warden.email})</option>
                  ))}
                </Select>
              </div>

              <div className="rounded-2xl border border-brand-border/70 bg-brand-surface/40 p-4">
                <div className="text-xs font-bold uppercase tracking-[0.12em] text-brand-muted mb-2">Assigned Wardens</div>
                {floorWardens.length > 0 ? (
                  <div className="flex flex-wrap gap-2">
                    {floorWardens.map(item => (
                      <Badge key={`${item.wing}-${item.warden_id}`} variant="primary">
                        {item.wing === 'left' ? 'Left Wing' : 'Right Wing'}: {item.warden_name}
                      </Badge>
                    ))}
                  </div>
                ) : (
                  <p className="text-sm text-brand-muted">No wardens assigned to this floor.</p>
                )}
              </div>
            </>
          )}
        </div>
      </SectionCard>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { studentsAPI, roomsAPI, allocationsAPI } from '../../../services/api';
import { Input, Select, Textarea, Modal } from '../../../components/ui';
import BulkUploadModal from '../../../components/ui/BulkUploadModal';
import { Upload } from 'lucide-react';

const COLORS = {
  primarybg: '#EEF1F9',
  secondarybg: '#FFFFFF',
  primary: '#7D53F6',
  primarydull: '#9F74F7',
  green: '#008000',
  pending: '#F0B041',
  red: '#DC2626',
  primarytext: '#000000',
  secondarytext: '#5F6388',
  scroll: '#D1D1D1',
  scrollHover: '#9CA3AF',
  skyblue: '#0388FC',
};

const DEPTS = ['CSE', 'ECE', 'EEE', 'MECH', 'CIVIL', 'IT', 'AIDS', 'AIML', 'CSD'];

const defaultForm = {
  name: '',
  register_no: '',
  department: 'CSE',
  year: 1,
  phone: '',
  email: '',
  address: '',
  joined_date: '',
};

const pageSize = 15;

export default function StudentsPage() {
  const [students, setStudents] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);

  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({
    dept: '',
    year: '',
  });
  const [modal, setModal] = useState(null);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [selected, setSelected] = useState(null);
  const [form, setForm] = useState(defaultForm);
  const [saving, setSaving] = useState(false);
  const [rooms, setRooms] = useState([]);
  const [allotRoomId, setAllotRoomId] = useState('');

  const loadStudents = useCallback(() => {
    setLoading(true);

    studentsAPI
      .getAll({
        search,
        ...filters,
        page,
        limit: pageSize,
      })
      .then((res) => {
        setStudents(res.data.data || []);
        setTotal(res.data.total || 0);
      })
      .catch(() => {
        toast.error('Failed to load students.');
      })
      .finally(() => {
        setLoading(false);
      });
  }, [search, filters, page]);

  useEffect(() => {
    loadStudents();
  }, [loadStudents]);

  const resetModalState = () => {
    setModal(null);
    setSelected(null);
    setAllotRoomId('');
    setRooms([]);
  };

  const handleInput = (key, value) => {
    setForm((prev) => ({
      ...prev,
      [key]: value,
    }));
  };

  const buildStudentPayload = () => ({
    name: form.name.trim(),
    register_no: form.register_no.trim().toUpperCase(),
    department: form.department,
    year: Number(form.year),
    phone: form.phone.trim(),
    email: form.email.trim(),
    address: form.address.trim(),
    joined_date: form.joined_date || null,
  });

  const openAdd = () => {
    setSelected(null);
    setForm(defaultForm);
    setModal('add');
  };

  const openEdit = (student) => {
    setSelected(student);
    setForm({
      name: student.name || '',
      register_no: student.register_no || '',
      department: student.department || 'CSE',
      year: student.year || 1,
      phone: student.phone || '',
      email: student.email || '',
      address: student.address || '',
      joined_date: student.joined_date?.slice(0, 10) || '',
    });
    setModal('edit');
  };

  const openView = (student) => {
    setSelected(student);
    setModal('view');
  };

  const openAllot = async (student) => {
    try {
      setSelected(student);
      const res = await roomsAPI.getAll({ status: 'available' });
      const availableRooms = (res.data.data || []).filter(
        (room) => room.occupied < room.capacity
      );
      setRooms(availableRooms);
      setAllotRoomId('');
      setModal('allot');
    } catch {
      toast.error('Failed to load available rooms.');
    }
  };

  const handleSave = async () => {
    const payload = buildStudentPayload();

    if (!payload.name || !payload.register_no || !payload.department || !payload.year) {
      toast.error('Name, register number, department, and year are required.');
      return;
    }

    if (payload.phone && !/^\d{10}$/.test(payload.phone)) {
      toast.error('Phone number must be exactly 10 digits.');
      return;
    }

    if (payload.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(payload.email)) {
      toast.error('Enter a valid email address.');
      return;
    }

    setSaving(true);

    try {
      if (modal === 'add') {
        await studentsAPI.create(payload);
        toast.success('Student added successfully.');
      } else if (modal === 'edit' && selected?.id) {
        await studentsAPI.update(selected.id, payload);
        toast.success('Student updated successfully.');
      }

      resetModalState();
      loadStudents();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Unable to save student.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this student record?')) return;

    try {
      await studentsAPI.delete(id);
      toast.success('Student deleted successfully.');
      loadStudents();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Delete failed.');
    }
  };

  // eslint-disable-next-line no-unused-vars
  const handleExport = async () => {
    try {
      const res = await studentsAPI.exportCSV();
      const blob = new Blob([res.data], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);

      const a = document.createElement('a');
      a.href = url;
      a.download = 'students.csv';
      a.click();

      URL.revokeObjectURL(url);
      toast.success('CSV exported successfully.');
    } catch {
      toast.error('Export failed.');
    }
  };

  const handleAllocate = async () => {
    if (!selected?.id || !allotRoomId) return;

    setSaving(true);
    try {
      await allocationsAPI.allocate({
        student_id: selected.id,
        room_id: Number(allotRoomId),
      });

      toast.success('Room allocated successfully.');
      resetModalState();
      loadStudents();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Allocation failed.');
    } finally {
      setSaving(false);
    }
  };

  const totalPages = Math.ceil(total / pageSize);

  const FormBody = () => (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
      <div className="md:col-span-2">
        <Input
          label="Full Name"
          value={form.name}
          onChange={(e) => handleInput('name', e.target.value)}
          placeholder="Enter full name"
        />
      </div>

      <Input
        label="Register No"
        value={form.register_no}
        onChange={(e) => handleInput('register_no', e.target.value)}
        placeholder="e.g. 22CS001"
        disabled={modal === 'edit'}
      />

      <Select
        label="Department"
        value={form.department}
        onChange={(e) => handleInput('department', e.target.value)}
      >
        {DEPTS.map((dept) => (
          <option key={dept} value={dept}>
            {dept}
          </option>
        ))}
      </Select>

      <Select
        label="Year"
        value={form.year}
        onChange={(e) => handleInput('year', Number(e.target.value))}
      >
        {[1, 2, 3, 4].map((year) => (
          <option key={year} value={year}>
            Year {year}
          </option>
        ))}
      </Select>

      <Input
        label="Phone Number"
        value={form.phone}
        onChange={(e) => handleInput('phone', e.target.value)}
        placeholder="10-digit mobile number"
      />

      <Input
        label="Email Address"
        type="email"
        value={form.email}
        onChange={(e) => handleInput('email', e.target.value)}
        placeholder="student@email.com"
      />

      <Input
        label="Joining Date"
        type="date"
        value={form.joined_date}
        onChange={(e) => handleInput('joined_date', e.target.value)}
      />

      <div className="md:col-span-2">
        <Textarea
          label="Address"
          value={form.address}
          onChange={(e) => handleInput('address', e.target.value)}
          placeholder="Enter student address"
        />
      </div>
    </div>
  );

  return (
    <div
      className="min-h-screen p-6 md:p-8"
      style={{
        background: 'transparent',
        color: COLORS.primarytext,
      }}
    >
      <div className="max-w-7xl mx-auto space-y-6">
        <div
          className="rounded-[28px] p-6 md:p-8 border shadow-sm"
          style={{
            backgroundColor: COLORS.secondarybg,
            borderColor: '#D8DCF0',
          }}
        >
          <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-5 mb-8">
            <div>
              <p
                className="text-sm font-semibold uppercase tracking-[2px]"
                style={{ color: COLORS.skyblue }}
              >
                Hostel Management
              </p>
              <h1
                className="text-3xl md:text-4xl font-bold mt-1"
                style={{ color: COLORS.primary }}
              >
                Student Records
              </h1>
              <p className="text-sm mt-2" style={{ color: COLORS.secondarytext }}>
                Manage student details and room allocation in one place.
              </p>
            </div>

            <div className="flex flex-wrap gap-3">
              <button
                  onClick={() => setIsBulkModalOpen(true)}
                  className="px-5 py-3 rounded-xl text-sm font-semibold border transition-all flex items-center gap-2"
                  style={{
                    borderColor: '#D8DCF0',
                    backgroundColor: COLORS.secondarybg,
                    color: COLORS.primarytext,
                  }}
                >
                  <Upload size={16} />
                  Import Students
                </button>

              <button
                onClick={openAdd}
                className="px-5 py-3 rounded-xl text-sm font-semibold transition-all"
                style={{
                  backgroundColor: COLORS.primary,
                  color: COLORS.secondarybg,
                  boxShadow: '0 10px 25px rgba(125, 83, 246, 0.25)',
                }}
              >
                + Add Student
              </button>
            </div>
          </div>

          <div
            className="rounded-2xl p-4 md:p-5 border mb-6"
            style={{
              backgroundColor: '#F9FAFD',
              borderColor: '#D8DCF0',
            }}
          >
            <div className="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr_1fr] gap-3">
              <div className="relative">
                <span
                  className="absolute left-4 top-1/2 -translate-y-1/2 text-sm"
                  style={{ color: COLORS.secondarytext }}
                >
                  🔍
                </span>
                <input
                  type="text"
                  value={search}
                  placeholder="Search by name, register no, or room..."
                  onChange={(e) => {
                    setSearch(e.target.value);
                    setPage(1);
                  }}
                  className="w-full rounded-xl py-3 pl-11 pr-4 text-sm outline-none border"
                  style={{
                    backgroundColor: COLORS.secondarybg,
                    borderColor: '#D8DCF0',
                    color: COLORS.primarytext,
                  }}
                />
              </div>

              <select
                value={filters.dept}
                onChange={(e) => {
                  setFilters((prev) => ({ ...prev, dept: e.target.value }));
                  setPage(1);
                }}
                className="rounded-xl px-4 py-3 text-sm outline-none border"
                style={{
                  backgroundColor: COLORS.secondarybg,
                  borderColor: '#D8DCF0',
                  color: COLORS.primarytext,
                }}
              >
                <option value="">All Departments</option>
                {DEPTS.map((dept) => (
                  <option key={dept} value={dept}>
                    {dept}
                  </option>
                ))}
              </select>

              <select
                value={filters.year}
                onChange={(e) => {
                  setFilters((prev) => ({ ...prev, year: e.target.value }));
                  setPage(1);
                }}
                className="rounded-xl px-4 py-3 text-sm outline-none border"
                style={{
                  backgroundColor: COLORS.secondarybg,
                  borderColor: '#D8DCF0',
                  color: COLORS.primarytext,
                }}
              >
                <option value="">All Years</option>
                {[1, 2, 3, 4].map((year) => (
                  <option key={year} value={year}>
                    Year {year}
                  </option>
                ))}
              </select>

            </div>
          </div>

          <div
            className="rounded-2xl overflow-hidden border"
            style={{
              borderColor: '#D8DCF0',
              backgroundColor: COLORS.secondarybg,
            }}
          >
            <div className="overflow-x-auto">
              <table className="w-full min-w-[1100px] text-sm">
                <thead>
                  <tr style={{ backgroundColor: COLORS.primarybg }}>
                    {[
                      'Roll No',
                      'Student Name',
                      'Department & Year',
                      'Room',
                      'Phone',
                      'Actions',
                    ].map((head) => (
                      <th
                        key={head}
                        className="px-5 py-4 text-left text-[11px] uppercase tracking-[1.4px] font-bold border-b"
                        style={{
                          color: COLORS.primary,
                          borderColor: '#D8DCF0',
                        }}
                      >
                        {head}
                      </th>
                    ))}
                  </tr>
                </thead>

                <tbody>
                  {loading ? (
                    <tr>
                      <td
                        colSpan="6"
                        className="text-center py-12"
                        style={{ color: COLORS.secondarytext }}
                      >
                        Loading student records...
                      </td>
                    </tr>
                  ) : students.length === 0 ? (
                    <tr>
                      <td
                        colSpan="6"
                        className="text-center py-12"
                        style={{ color: COLORS.secondarytext }}
                      >
                        No student records found.
                      </td>
                    </tr>
                  ) : (
                    students.map((student) => (
                      <tr
                        key={student.id}
                        className="hover:bg-[#F8F9FD] transition-colors"
                        style={{ borderBottom: '1px solid #D8DCF0' }}
                      >
                        <td className="px-5 py-4 font-mono text-[12px]">
                          {student.register_no}
                        </td>

                        <td className="px-5 py-4">
                          <div className="flex items-center gap-3">
                            <div
                              className="w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold"
                              style={{
                                backgroundColor: 'rgba(125,83,246,0.12)',
                                color: COLORS.primary,
                              }}
                            >
                              {student.name
                                ?.split(' ')
                                .map((word) => word[0])
                                .join('')
                                .slice(0, 2)}
                            </div>
                            <div>
                              <p className="font-semibold">{student.name}</p>
                              <p
                                className="text-[12px]"
                                style={{ color: COLORS.secondarytext }}
                              >
                                {student.email || 'No email'}
                              </p>
                            </div>
                          </div>
                        </td>

                        <td className="px-5 py-4" style={{ color: COLORS.secondarytext }}>
                          {student.department} | Year {student.year}
                        </td>

                        <td className="px-5 py-4">
                          {student.room_number
                            ? `${student.block?.[0] || ''}-${student.room_number}`
                            : '-'}
                        </td>

                        <td
                          className="px-5 py-4 font-mono text-[12px]"
                          style={{ color: COLORS.secondarytext }}
                        >
                          {student.phone || '-'}
                        </td>

                        <td className="px-5 py-4">
                          <div className="flex flex-wrap gap-2">
                            <button
                              onClick={() => openView(student)}
                              className="px-3 py-1.5 rounded-lg text-[12px] font-semibold"
                              style={{
                                backgroundColor: COLORS.skyblue,
                                color: COLORS.secondarybg,
                              }}
                            >
                              View
                            </button>

                            <button
                              onClick={() => openEdit(student)}
                              className="px-3 py-1.5 rounded-lg text-[12px] font-semibold"
                              style={{
                                backgroundColor: COLORS.primary,
                                color: COLORS.secondarybg,
                              }}
                            >
                              Edit
                            </button>

                            <button
                              onClick={() => handleDelete(student.id)}
                              className="px-3 py-1.5 rounded-lg text-[12px] font-semibold"
                              style={{
                                backgroundColor: COLORS.red,
                                color: COLORS.secondarybg,
                              }}
                            >
                              Delete
                            </button>

                            {!student.room_id && (
                              <button
                                onClick={() => openAllot(student)}
                                className="px-3 py-1.5 rounded-lg text-[12px] font-semibold"
                                style={{
                                  backgroundColor: COLORS.pending,
                                  color: COLORS.secondarybg,
                                }}
                              >
                                Assign
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            {total > pageSize && (
              <div
                className="flex flex-col md:flex-row items-center justify-between gap-3 px-5 py-4 border-t"
                style={{ borderColor: '#D8DCF0' }}
              >
                <p className="text-sm" style={{ color: COLORS.secondarytext }}>
                  Showing {(page - 1) * pageSize + 1}-{Math.min(page * pageSize, total)} of{' '}
                  {total}
                </p>

                <div className="flex items-center gap-2">
                  <button
                    disabled={page === 1}
                    onClick={() => setPage((prev) => prev - 1)}
                    className="px-4 py-2 rounded-lg text-sm font-semibold border disabled:opacity-50"
                    style={{
                      borderColor: '#D8DCF0',
                      backgroundColor: COLORS.secondarybg,
                    }}
                  >
                    Previous
                  </button>

                  <span
                    className="px-3 text-sm font-medium"
                    style={{ color: COLORS.secondarytext }}
                  >
                    {page} / {totalPages}
                  </span>

                  <button
                    disabled={page === totalPages}
                    onClick={() => setPage((prev) => prev + 1)}
                    className="px-4 py-2 rounded-lg text-sm font-semibold border disabled:opacity-50"
                    style={{
                      borderColor: '#D8DCF0',
                      backgroundColor: COLORS.secondarybg,
                    }}
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <BulkUploadModal
        isOpen={isBulkModalOpen}
        onClose={() => setIsBulkModalOpen(false)}
        title="Import Students"
        columns={[
          { key: 'name', label: 'Name' },
          { key: 'register_no', label: 'Register No' },
          { key: 'department', label: 'Department' },
          { key: 'year', label: 'Year' },
          { key: 'phone', label: 'Phone' },
          { key: 'email', label: 'Email' },
          { key: 'address', label: 'Address' }
        ]}
        sampleData={[
          { name: 'John Doe', register_no: '22CS001', department: 'CSE', year: '1', phone: '1234567890', email: 'john@example.com', address: '123 Main St' }
        ]}
        uploadEndpoint="/bulk/students"
        onSuccess={() => { setIsBulkModalOpen(false); loadStudents(); }}
      />

      <Modal
        open={modal === 'add' || modal === 'edit'}
        onClose={resetModalState}
        title={modal === 'add' ? 'Add New Student' : 'Edit Student'}
        size="lg"
      >
        <FormBody />

        <div className="flex justify-end gap-3 mt-4 pt-4 border-t border-[#D8DCF0]">
          <button
            onClick={resetModalState}
            className="px-5 py-2.5 rounded-xl text-sm font-semibold border"
            style={{
              borderColor: '#D8DCF0',
              backgroundColor: COLORS.secondarybg,
              color: COLORS.primarytext,
            }}
          >
            Cancel
          </button>

          <button
            onClick={handleSave}
            disabled={saving}
            className="px-5 py-2.5 rounded-xl text-sm font-semibold disabled:opacity-60"
            style={{
              backgroundColor: COLORS.primary,
              color: COLORS.secondarybg,
            }}
          >
            {modal === 'add' ? 'Add Student' : 'Save Changes'}
          </button>
        </div>
      </Modal>

      <Modal
        open={modal === 'view'}
        onClose={resetModalState}
        title="Student Profile"
        size="md"
      >
        {selected && (
          <div className="space-y-5">
            <div className="flex items-center gap-4 pb-4 border-b border-[#D8DCF0]">
              <div
                className="w-16 h-16 rounded-full flex items-center justify-center text-xl font-bold"
                style={{
                  backgroundColor: COLORS.primary,
                  color: COLORS.secondarybg,
                }}
              >
                {selected.name
                  ?.split(' ')
                  .map((word) => word[0])
                  .join('')
                  .slice(0, 2)}
              </div>

              <div>
                <h3 className="text-xl font-bold" style={{ color: COLORS.primary }}>
                  {selected.name}
                </h3>
                <p
                  className="font-mono text-[12px]"
                  style={{ color: COLORS.secondarytext }}
                >
                  {selected.register_no}
                </p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 text-sm">
              {[
                ['Department', selected.department],
                ['Year', `Year ${selected.year}`],
                ['Phone', selected.phone || 'N/A'],
                ['Email', selected.email || 'N/A'],
                [
                  'Room',
                  selected.room_number
                    ? `${selected.room_number} (Block ${selected.block})`
                    : 'Unassigned',
                ],
                ['Joined Date', selected.joined_date?.slice(0, 10) || 'N/A'],
              ].map(([label, value]) => (
                <div key={label}>
                  <p
                    className="text-[11px] uppercase tracking-[1.5px] font-bold mb-1.5"
                    style={{ color: COLORS.secondarytext }}
                  >
                    {label}
                  </p>
                  <p style={{ color: COLORS.primarytext }}>{value}</p>
                </div>
              ))}

              {selected.address && (
                <div className="md:col-span-2">
                  <p
                    className="text-[11px] uppercase tracking-[1.5px] font-bold mb-1.5"
                    style={{ color: COLORS.secondarytext }}
                  >
                    Address
                  </p>
                  <p style={{ color: COLORS.primarytext }}>{selected.address}</p>
                </div>
              )}
            </div>

            <div className="flex flex-wrap gap-2 pt-4 border-t border-[#D8DCF0]">
              <button
                onClick={() => openEdit(selected)}
                className="px-4 py-2 rounded-lg text-sm font-semibold"
                style={{
                  backgroundColor: COLORS.skyblue,
                  color: COLORS.secondarybg,
                }}
              >
                Edit
              </button>

              {!selected.room_id && (
                <button
                  onClick={() => openAllot(selected)}
                  className="px-4 py-2 rounded-lg text-sm font-semibold"
                  style={{
                    backgroundColor: COLORS.primary,
                    color: COLORS.secondarybg,
                  }}
                >
                  Allocate Room
                </button>
              )}
            </div>
          </div>
        )}
      </Modal>

      <Modal
        open={modal === 'allot'}
        onClose={resetModalState}
        title="Allocate Room"
        size="md"
      >
        {selected && (
          <div className="space-y-5">
            <p className="text-sm" style={{ color: COLORS.secondarytext }}>
              Allocating room for{' '}
              <span className="font-semibold" style={{ color: COLORS.primarytext }}>
                {selected.name}
              </span>
            </p>

            <div>
              <label
                className="block text-[12px] font-semibold mb-2"
                style={{ color: COLORS.primary }}
              >
                Select Available Room
              </label>

              <select
                value={allotRoomId}
                onChange={(e) => setAllotRoomId(e.target.value)}
                className="w-full rounded-xl px-4 py-3 text-sm outline-none border"
                style={{
                  backgroundColor: COLORS.secondarybg,
                  borderColor: '#D8DCF0',
                  color: COLORS.primarytext,
                }}
              >
                <option value="">Choose a room</option>
                {rooms.map((room) => (
                  <option key={room.id} value={room.id}>
                    {room.room_number} (Block {room.block}) | {room.occupied}/
                    {room.capacity} occupied
                  </option>
                ))}
              </select>
            </div>

            <div className="flex justify-end gap-3 pt-5 border-t border-[#D8DCF0]">
              <button
                onClick={resetModalState}
                className="px-5 py-2.5 rounded-xl text-sm font-semibold border"
                style={{
                  borderColor: '#D8DCF0',
                  backgroundColor: COLORS.secondarybg,
                  color: COLORS.primarytext,
                }}
              >
                Cancel
              </button>

              <button
                disabled={!allotRoomId || saving}
                onClick={handleAllocate}
                className="px-5 py-2.5 rounded-xl text-sm font-semibold disabled:opacity-50"
                style={{
                  backgroundColor: COLORS.green,
                  color: COLORS.secondarybg,
                }}
              >
                Allocate
              </button>
            </div>
          </div>
        )}
      </Modal>


    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { usersAPI } from '../../../services/api';
import { Table, Badge, Button, Input, Select, Modal, PageHeader, EmptyState } from '../../../components/ui';
import { format } from 'date-fns';
import { UsersIcon, UserPlus, ShieldIcon, Wrench, Trash2, Edit2 } from 'lucide-react';

export default function UsersPage() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const [roleFilter, setRoleFilter] = useState('');
  const [search, setSearch] = useState('');
  
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState(null);
  const [formData, setFormData] = useState({ name: '', email: '', password: '', role: 'warden', specialty: '' });
  const [submitting, setSubmitting] = useState(false);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await usersAPI.getAll({ role: roleFilter, search });
      setUsers(res.data.data || []);
    } catch (err) {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(fetchUsers, 300);
    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [roleFilter, search]);

  const handleOpenForm = (user = null) => {
    if (user) {
      setEditId(user.id);
      setFormData({ name: user.name, email: user.email, password: '', role: user.role, specialty: user.specialty || '' });
    } else {
      setEditId(null);
      setFormData({ name: '', email: '', password: '', role: 'warden', specialty: '' });
    }
    setShowForm(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      const payload = { ...formData };
      if (!payload.password) delete payload.password; // Do not send empty password on update
      if (payload.role !== 'caretaker') delete payload.specialty;

      if (editId) {
        await usersAPI.update(editId, payload);
        toast.success('User updated successfully');
      } else {
        if (!payload.password) return toast.error('Password is required for new users');
        await usersAPI.create(payload);
        toast.success('User created successfully');
      }
      setShowForm(false);
      fetchUsers();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save user');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this user? This cannot be undone.')) return;
    try {
      await usersAPI.delete(id);
      toast.success('User deleted');
      fetchUsers();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete user');
    }
  };

  const columns = [
    { key: 'name', label: 'User Details', render: (val, row) => (
      <div>
        <div className="font-semibold text-gray-900 leading-tight">{val}</div>
        <div className="text-xs text-gray-500 mt-0.5">{row.email}</div>
      </div>
    )},
    { key: 'role', label: 'Role Profile', render: (val, row) => (
      <div className="flex items-center gap-2">
         {val === 'admin' ? <ShieldIcon className="w-4 h-4 text-purple-500" /> : val === 'warden' ? <UsersIcon className="w-4 h-4 text-blue-500" /> : val === 'caretaker' ? <Wrench className="w-4 h-4 text-emerald-500" /> : <UsersIcon className="w-4 h-4 text-gray-400" />}
         <div>
            <Badge variant={val === 'admin' ? 'purple' : val === 'warden' ? 'info' : val === 'caretaker' ? 'success' : 'default'} className="capitalize">{val === 'caretaker' ? 'Staff' : val}</Badge>
            {row.specialty && <div className="text-[10px] uppercase font-bold text-gray-500 mt-1 pl-1 tracking-wider">{row.specialty.replace('_', ' ')}</div>}
         </div>
      </div>
    )},
    { key: 'has_google', label: 'Auth', render: (val) => val ? <Badge variant="outline" className="border-blue-200 text-blue-700 bg-blue-50">Google</Badge> : <Badge variant="outline">Password</Badge> },
    { key: 'created_at', label: 'Joined', render: (val) => <span className="text-sm text-gray-600">{format(new Date(val), 'MMM yyyy')}</span> },
    { key: 'actions', label: '', render: (_, row) => (
      <div className="flex justify-end gap-2">
        <Button variant="ghost" className="h-8 w-8 !p-0" onClick={() => handleOpenForm(row)}><Edit2 className="w-4 h-4 text-gray-500" /></Button>
        <Button variant="ghost" className="h-8 w-8 !p-0 hover:bg-red-50" onClick={() => handleDelete(row.id)}><Trash2 className="w-4 h-4 text-red-500" /></Button>
      </div>
    )}
  ];

  return (
    <div className="space-y-6">
      <PageHeader
        eyebrow="System Administration"
        title="User Management"
        description="Add and manage administrative users, wardens, and support staff."
        actions={<Button onClick={() => handleOpenForm()} className="gap-2"><UserPlus className="w-4 h-4"/> Add User</Button>}
      />

      <div className="flex flex-col sm:flex-row gap-4 mb-2">
         <Input placeholder="Search name or email..." value={search} onChange={e => setSearch(e.target.value)} className="w-full sm:w-64 bg-white" />
         <Select value={roleFilter} onChange={e => setRoleFilter(e.target.value)} className="w-full sm:w-48 bg-white">
           <option value="">All Roles</option>
           <option value="admin">Administrators</option>
           <option value="warden">Wardens</option>
           <option value="caretaker">Support Staff</option>
         </Select>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
         {users.length > 0 ? (
           <Table columns={columns} data={users} loading={loading} />
         ) : (
           <EmptyState 
             title="No Users Found" 
             description="No users matched your search criteria." 
             icon={<UsersIcon className="w-10 h-10 text-gray-300" />} 
           />
         )}
      </div>

      <Modal open={showForm} onClose={() => setShowForm(false)} title={editId ? "Edit User Profile" : "Register New User"} size="md">
         <form onSubmit={handleSubmit} className="space-y-4">
            <Input label="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />
            <Input type="email" label="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} required />
            <Input type="password" label={editId ? "Password (leave blank to keep current)" : "Initial Password"} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required={!editId} autoComplete="new-password" />
            
            <div className="pt-2">
              <label className="text-sm font-medium text-gray-700 mb-3 block">System Role</label>
              <div className="grid grid-cols-3 gap-3">
                 {[
                   { id: 'admin', label: 'Admin', icon: <ShieldIcon className="w-4 h-4 mb-2 mx-auto"/>, color: 'purple' },
                   { id: 'warden', label: 'Warden', icon: <UsersIcon className="w-4 h-4 mb-2 mx-auto"/>, color: 'blue' },
                   { id: 'caretaker', label: 'Staff', icon: <Wrench className="w-4 h-4 mb-2 mx-auto"/>, color: 'emerald' },
                 ].map(r => (
                   <label key={r.id} className={`cursor-pointer border-2 rounded-xl p-3 text-center transition-all ${formData.role === r.id ? `border-${r.color}-500 bg-${r.color}-50 text-${r.color}-700` : 'border-gray-100 text-gray-500 hover:border-gray-300 hover:bg-gray-50'}`}>
                      <input type="radio" className="hidden" name="role" value={r.id} checked={formData.role === r.id} onChange={e => setFormData({...formData, role: e.target.value})} />
                      {r.icon}
                      <span className="text-xs font-bold uppercase tracking-wider">{r.label}</span>
                   </label>
                 ))}
              </div>
            </div>

            {formData.role === 'caretaker' && (
              <Select label="Staff Specialty (For Smart Routing)" value={formData.specialty} onChange={e => setFormData({...formData, specialty: e.target.value})}>
                <option value="">General Support / No Specialty</option>
                <option value="electrician">Electrician</option>
                <option value="plumber">Plumber</option>
                <option value="carpenter">Carpenter</option>
                <option value="cleaner">Housekeeping / Cleaner</option>
                <option value="network_admin">Network & IT</option>
              </Select>
            )}

            <div className="flex justify-end gap-3 pt-6 border-t border-gray-100 mt-6">
               <Button type="button" variant="outline" onClick={() => setShowForm(false)}>Cancel</Button>
               <Button type="submit" loading={submitting}>{editId ? 'Save Changes' : 'Create User'}</Button>
            </div>
         </form>
      </Modal>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import toast from 'react-hot-toast';
import { caretakerAPI } from '../../services/api';
import { Spinner, Badge } from '../../components/ui';
import { Search, Filter } from 'lucide-react';
import { format } from 'date-fns';

const COLORS = {
  primary: '#7D53F6',
  pending: '#F0B041',
  inProgress: '#0388FC',
  resolved: '#008000',
  secondarytext: '#5F6388',
};

export default function CaretakerComplaints() {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [updating, setUpdating] = useState({});
  const pageSize = 15;

  const loadComplaints = useCallback(() => {
    setLoading(true);
    caretakerAPI.getComplaints({ status: filterStatus, page, limit: pageSize })
      .then(r => {
        setComplaints(r.data.data || []);
        setTotal(r.data.total || 0);
      })
      .catch(() => toast.error('Failed to load complaints'))
      .finally(() => setLoading(false));
  }, [filterStatus, page]);

  useEffect(() => {
    loadComplaints();
  }, [loadComplaints]);

  const handleStatusChange = async (complaintId, newStatus) => {
    setUpdating(prev => ({ ...prev, [complaintId]: true }));
    try {
      await caretakerAPI.updateComplaint(complaintId, { status: newStatus });
      toast.success(`Complaint status updated to ${newStatus}`);
      loadComplaints();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to update status');
    } finally {
      setUpdating(prev => ({ ...prev, [complaintId]: false }));
    }
  };

  const filterComplaints = complaints.filter(c =>
    !search || c.title?.toLowerCase().includes(search.toLowerCase()) ||
    c.student_name?.toLowerCase().includes(search.toLowerCase())
  );

  const totalPages = Math.ceil(total / pageSize);
  const statusColors = {
    pending: COLORS.pending,
    in_progress: COLORS.inProgress,
    resolved: COLORS.resolved,
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-2xl p-6 md:p-8 bg-white border border-gray-50 shadow-sm"
      >
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Complaint Management</h1>
        <p className="text-sm text-gray-600">View and manage all student complaints</p>
      </motion.div>

      {/* Filters */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.1 }}
        className="rounded-2xl p-6 bg-white border border-gray-100 shadow-sm"
      >
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search by title or student name..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#7D53F6]"
            />
          </div>

          <select
            value={filterStatus}
            onChange={(e) => {
              setFilterStatus(e.target.value);
              setPage(1);
            }}
            className="px-4 py-3 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#7D53F6]"
          >
            <option value="">All Status</option>
            <option value="pending">Pending</option>
            <option value="in_progress">In Progress</option>
            <option value="resolved">Resolved</option>
          </select>

          <div className="flex items-center justify-between text-sm text-gray-600">
            <span>{filterComplaints.length} of {total} complaints</span>
            <Filter className="w-4 h-4" />
          </div>
        </div>
      </motion.div>

      {/* Complaints Table */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
        className="rounded-2xl overflow-hidden border border-gray-100 shadow-sm bg-white"
      >
        <div className="overflow-x-auto">
          <table className="w-full min-w-[900px]">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                {['Title', 'Student', 'Room', 'Priority', 'Status', 'Date', 'Action'].map(header => (
                  <th key={header} className="px-6 py-4 text-left text-xs font-bold uppercase text-gray-600 tracking-wider">
                    {header}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td colSpan="7" className="px-6 py-8 text-center">
                    <Spinner size="md" />
                  </td>
                </tr>
              ) : filterComplaints.length === 0 ? (
                <tr>
                  <td colSpan="7" className="px-6 py-8 text-center text-gray-500">
                    No complaints found
                  </td>
                </tr>
              ) : (
                filterComplaints.map((complaint, i) => (
                  <motion.tr
                    key={complaint.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className="border-b border-gray-100 hover:bg-gray-50 transition-colors"
                  >
                    <td className="px-6 py-4">
                      <div className="font-medium text-gray-900 truncate max-w-xs">{complaint.title}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-600">{complaint.student_name || 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-600">{complaint.room_number || 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <Badge style={{
                        backgroundColor: complaint.priority === 'high' ? '#FEE2E2' :
                                        complaint.priority === 'medium' ? '#FEF3C7' : '#DBEAFE',
                        color: complaint.priority === 'high' ? '#DC2626' :
                               complaint.priority === 'medium' ? '#D97706' : '#1E40AF',
                      }}>
                        {complaint.priority?.toUpperCase() || 'MEDIUM'}
                      </Badge>
                    </td>
                    <td className="px-6 py-4">
                      <Badge style={{
                        backgroundColor: `${statusColors[complaint.status]}20`,
                        color: statusColors[complaint.status],
                      }}>
                        {complaint.status === 'pending' ? '⏳ Pending' :
                         complaint.status === 'in_progress' ? '🔧 In Progress' :
                         '✓ Resolved'}
                      </Badge>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      {format(new Date(complaint.created_at), 'dd MMM yyyy')}
                    </td>
                    <td className="px-6 py-4">
                      <select
                        value={complaint.status}
                        onChange={(e) => handleStatusChange(complaint.id, e.target.value)}
                        disabled={updating[complaint.id]}
                        className="px-3 py-1.5 text-xs border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#7D53F6] disabled:opacity-50 cursor-pointer"
                      >
                        <option value="pending">Pending</option>
                        <option value="in_progress">In Progress</option>
                        <option value="resolved">Resolved</option>
                      </select>
                    </td>
                  </motion.tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {total > pageSize && (
          <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-between bg-gray-50">
            <span className="text-sm text-gray-600">
              Page {page} of {totalPages}
            </span>
            <div className="flex gap-2">
              <button
                disabled={page === 1}
                onClick={() => setPage(1)}
                className="px-4 py-2 border border-gray-200 rounded-lg text-sm font-medium disabled:opacity-50 hover:bg-gray-100"
              >
                First
              </button>
              <button
                disabled={page === 1}
                onClick={() => setPage(page - 1)}
                className="px-4 py-2 border border-gray-200 rounded-lg text-sm font-medium disabled:opacity-50 hover:bg-gray-100"
              >
                Previous
              </button>
              <button
                disabled={page === totalPages}
                onClick={() => setPage(page + 1)}
                className="px-4 py-2 border border-gray-200 rounded-lg text-sm font-medium disabled:opacity-50 hover:bg-gray-100"
              >
                Next
              </button>
              <button
                disabled={page === totalPages}
                onClick={() => setPage(totalPages)}
                className="px-4 py-2 border border-gray-200 rounded-lg text-sm font-medium disabled:opacity-50 hover:bg-gray-100"
              >
                Last
              </button>
            </div>
          </div>
        )}
      </motion.div>
    </div>
  );
}

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import toast from 'react-hot-toast';
import { CheckCircle2, Filter, Search, Wrench } from 'lucide-react';
import { format } from 'date-fns';
import { caretakerAPI } from '../../services/api';
import { Badge, Button, EmptyState, Input, PanelShell, PortalHero, Select, Spinner } from '../../components/ui';

const PAGE_SIZE = 15;

export default function CaretakerComplaintsPortal() {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [updating, setUpdating] = useState({});

  const loadComplaints = useCallback(() => {
    setLoading(true);
    caretakerAPI.getComplaints({ status: filterStatus, page, limit: PAGE_SIZE })
      .then(response => {
        setComplaints(response.data.data || []);
        setTotal(response.data.total || 0);
      })
      .catch(() => toast.error('Failed to load complaints'))
      .finally(() => setLoading(false));
  }, [filterStatus, page]);

  useEffect(() => {
    loadComplaints();
  }, [loadComplaints]);

  const filteredComplaints = useMemo(() => complaints.filter(item => (
    !search ||
    item.title?.toLowerCase().includes(search.toLowerCase()) ||
    item.student_name?.toLowerCase().includes(search.toLowerCase())
  )), [complaints, search]);

  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));

  const handleStatusChange = async (complaintId, newStatus) => {
    setUpdating(current => ({ ...current, [complaintId]: true }));
    try {
      await caretakerAPI.updateComplaint(complaintId, { status: newStatus });
      toast.success(`Complaint updated to ${newStatus.replace('_', ' ')}`);
      loadComplaints();
    } catch (error) {
      toast.error(error?.response?.data?.message || 'Failed to update status');
    } finally {
      setUpdating(current => ({ ...current, [complaintId]: false }));
    }
  };

  return (
    <div className="space-y-6">
      <PortalHero
        eyebrow="Caretaker Queue"
        title="Complaint Management"
        description="Search, triage, and update student complaints from a cleaner service operations view."
        accent="orange"
        icon={<Wrench className="h-4 w-4" />}
      />

      <PanelShell title="Filters" description="Refine the complaint queue by resident name, issue title, or workflow status.">
        <div className="grid gap-4 lg:grid-cols-[1.2fr_0.7fr_auto]">
          <Input icon={<Search className="h-4 w-4" />} value={search} onChange={event => setSearch(event.target.value)} placeholder="Search by title or student name" className="h-14 rounded-[20px] bg-[#fbfbff] px-5" />
          <Select value={filterStatus} onChange={event => { setFilterStatus(event.target.value); setPage(1); }} className="h-14 rounded-[20px] bg-[#fbfbff] px-5">
            <option value="">All Status</option>
            <option value="pending">Pending</option>
            <option value="in_progress">In Progress</option>
            <option value="resolved">Resolved</option>
          </Select>
          <div className="flex items-center rounded-[20px] border border-brand-border/70 bg-[#fafbff] px-5 text-sm font-medium text-brand-muted">
            <Filter className="mr-2 h-4 w-4" />
            {filteredComplaints.length} of {total}
          </div>
        </div>
      </PanelShell>

      <PanelShell title="Complaint Queue" description="Update each complaint as it moves from pending to resolution.">
        {loading ? (
          <div className="flex justify-center py-16"><Spinner size="lg" className="text-orange-500" /></div>
        ) : filteredComplaints.length === 0 ? (
          <EmptyState title="No complaints found" description="Try a different search or filter to view more service records." icon={<CheckCircle2 className="h-10 w-10" />} />
        ) : (
          <div className="space-y-4">
            {filteredComplaints.map(complaint => (
              <div key={complaint.id} className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-5">
                <div className="flex flex-col gap-5 xl:flex-row xl:items-start xl:justify-between">
                  <div className="space-y-3">
                    <div className="flex flex-wrap items-center gap-2">
                      <div className="text-lg font-semibold text-brand-text">{complaint.title}</div>
                      <Badge variant={complaint.status === 'pending' ? 'warning' : complaint.status === 'in_progress' ? 'info' : 'success'}>
                        {complaint.status === 'in_progress' ? 'In Progress' : complaint.status}
                      </Badge>
                      <Badge variant={complaint.priority === 'high' ? 'danger' : complaint.priority === 'medium' ? 'warning' : 'info'}>
                        {(complaint.priority || 'medium').toUpperCase()}
                      </Badge>
                    </div>
                    <div className="text-sm text-brand-muted">
                      {complaint.student_name || 'Unknown Student'} • Room {complaint.room_number || 'N/A'} • {complaint.category || 'other'}
                    </div>
                    {complaint.description ? <p className="text-sm leading-7 text-brand-muted">{complaint.description}</p> : null}
                    <div className="text-xs font-medium uppercase tracking-[0.14em] text-brand-muted">
                      Created {format(new Date(complaint.created_at), 'dd MMM yyyy')}
                    </div>
                  </div>

                  <div className="w-full xl:max-w-[220px]">
                    <Select
                      value={complaint.status}
                      onChange={event => handleStatusChange(complaint.id, event.target.value)}
                      disabled={updating[complaint.id]}
                      className="h-12 rounded-[18px] bg-white"
                    >
                      <option value="pending">Pending</option>
                      <option value="in_progress">In Progress</option>
                      <option value="resolved">Resolved</option>
                    </Select>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {total > PAGE_SIZE ? (
          <div className="mt-6 flex flex-col gap-3 border-t border-brand-border/70 pt-6 sm:flex-row sm:items-center sm:justify-between">
            <div className="text-sm text-brand-muted">Page {page} of {totalPages}</div>
            <div className="flex gap-2">
              <Button variant="outline" size="sm" disabled={page === 1} onClick={() => setPage(current => Math.max(1, current - 1))}>Previous</Button>
              <Button variant="outline" size="sm" disabled={page === totalPages} onClick={() => setPage(current => Math.min(totalPages, current + 1))}>Next</Button>
            </div>
          </div>
        ) : null}
      </PanelShell>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { caretakerAPI } from '../../services/api';
import { Spinner, Badge, StatCard, PageHeader, Card } from '../../components/ui';
import { AlertCircle, CheckCircle2, Clock, Users, Building2, Home } from 'lucide-react';
import { format } from 'date-fns';

export default function CaretakerDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    caretakerAPI.getStats()
      .then(r => setData(r.data))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Spinner size="lg" className="text-orange-500" />
      </div>
    );
  }

  const stats = data?.stats || {};
  const recentComplaints = data?.recentComplaints || [];

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <PageHeader 
        title="Complaint Management Dashboard"
        description="Manage and resolve all hostel complaints from here."
        eyebrow="Caretaker Portal"
      />

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard title="Total Students" value={stats.totalStudents || 0} icon={<Users className="w-5 h-5" />} color="primary" />
        <StatCard title="Total Rooms" value={stats.totalRooms || 0} icon={<Building2 className="w-5 h-5" />} color="blue" />
        <StatCard title="Occupied Rooms" value={stats.occupiedRooms || 0} icon={<Home className="w-5 h-5" />} color="purple" />
        <StatCard title="Pending Issues" value={stats.pendingComplaints || 0} icon={<AlertCircle className="w-5 h-5" />} color="amber" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-1 p-6 h-full flex flex-col">
          <h2 className="text-lg font-bold text-gray-900 mb-6">Complaint Status</h2>
          <div className="space-y-4">
            <div className="flex items-center gap-4 bg-orange-50/50 p-4 rounded-xl border border-orange-100">
              <div className="w-12 h-12 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center">
                <AlertCircle className="w-6 h-6" />
              </div>
              <div>
                <div className="text-sm font-semibold text-gray-600">Pending</div>
                <div className="text-2xl font-bold text-gray-900">{stats.pendingComplaints || 0}</div>
              </div>
            </div>
            
            <div className="flex items-center gap-4 bg-blue-50/50 p-4 rounded-xl border border-blue-100">
              <div className="w-12 h-12 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center">
                <Clock className="w-6 h-6" />
              </div>
              <div>
                <div className="text-sm font-semibold text-gray-600">In Progress</div>
                <div className="text-2xl font-bold text-gray-900">{stats.inProgressComplaints || 0}</div>
              </div>
            </div>
          </div>
        </Card>

        <Card className="lg:col-span-2 p-6 h-full">
          <h2 className="text-lg font-bold text-gray-900 mb-6">Recent Complaints</h2>
          <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {recentComplaints.length > 0 ? (
              recentComplaints.map((complaint, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.1 }}
                  className="p-4 rounded-xl bg-slate-50 border border-gray-100 hover:border-brand-primary/30 transition-colors"
                >
                  <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3 mb-2">
                    <div className="flex-1 min-w-0">
                      <h3 className="font-semibold text-sm text-gray-900 truncate">{complaint.title}</h3>
                      <p className="text-sm text-gray-500 mt-0.5">
                        {complaint.student_name || 'Unknown Student'} • Room {complaint.room_number || 'N/A'}
                      </p>
                    </div>
                    <Badge 
                      variant={
                        complaint.status === 'pending' ? 'warning' :
                        complaint.status === 'in_progress' ? 'info' :
                        'success'
                      }
                      className="shrink-0 w-fit"
                    >
                      {complaint.status === 'pending' ? 'Pending' :
                       complaint.status === 'in_progress' ? 'In Progress' :
                       'Resolved'}
                    </Badge>
                  </div>
                  {complaint.description && (
                    <p className="text-sm text-gray-600 line-clamp-2 mb-3">{complaint.description}</p>
                  )}
                  <div className="flex items-center justify-between text-xs text-gray-400 font-medium pt-3 border-t border-gray-100">
                    <span className={`uppercase tracking-wider ${complaint.priority?.toLowerCase() === 'high' ? 'text-red-500' : ''}`}>
                      {complaint.priority || 'MEDIUM'} Priority
                    </span>
                    <span>{format(new Date(complaint.created_at), 'dd MMM yyyy')}</span>
                  </div>
                </motion.div>
              ))
            ) : (
              <div className="py-12 flex flex-col items-center text-center">
                <CheckCircle2 className="w-12 h-12 mb-3 text-emerald-500" />
                <p className="text-base font-bold text-gray-900">No complaints</p>
                <p className="text-sm text-gray-500 mt-1">All complaints are resolved!</p>
              </div>
            )}
          </div>
        </Card>
      </div>
    </div>
  );
}

