        eyebrow="Caretaker Portal"
        title="Facilities Operations"
        description="Track complaint flow, monitor room usage, and keep hostel service activity moving from a single caretaker dashboard."
        accent="orange"
        icon={<Wrench className="h-4 w-4" />}
      />

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <MetricPanel title="Total Students" value={stats.totalStudents || 0} helper="Residents on record" tone="orange" icon={<Wrench className="h-5 w-5" />} />
        <MetricPanel title="Total Rooms" value={stats.totalRooms || 0} helper="Hostel inventory" tone="blue" icon={<Building2 className="h-5 w-5" />} />
        <MetricPanel title="Occupied Rooms" value={stats.occupiedRooms || 0} helper="Rooms currently in use" tone="primary" icon={<Home className="h-5 w-5" />} />
        <MetricPanel title="Pending Issues" value={stats.pendingComplaints || 0} helper="Tickets needing action" tone="orange" icon={<AlertCircle className="h-5 w-5" />} />
      </div>

      <div className="grid gap-6 xl:grid-cols-[0.9fr_1.35fr]">
        <PanelShell title="Complaint Status" description="Current operational split for service desk tickets.">
          <div className="space-y-4">
            <div className="rounded-[26px] border border-orange-100 bg-orange-50 p-5">
              <div className="flex items-center justify-between">
                <div>
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-orange-600">Pending</div>
                  <div className="mt-3 font-display text-4xl font-black tracking-[-0.04em] text-brand-text">{stats.pendingComplaints || 0}</div>
                </div>
                <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-white text-orange-600"><AlertCircle className="h-5 w-5" /></div>
              </div>
            </div>

            <div className="rounded-[26px] border border-sky-100 bg-sky-50 p-5">
              <div className="flex items-center justify-between">
                <div>
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-sky-600">In Progress</div>
                  <div className="mt-3 font-display text-4xl font-black tracking-[-0.04em] text-brand-text">{stats.inProgressComplaints || 0}</div>
                </div>
                <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-white text-sky-600"><Clock className="h-5 w-5" /></div>
              </div>
            </div>
          </div>
        </PanelShell>

        <PanelShell title="Recent Complaints" description="Latest student complaints entering the caretaker queue.">
          {recentComplaints.length > 0 ? (
            <div className="space-y-4">
              {recentComplaints.map(complaint => (
                <div key={complaint.id} className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-5">
                  <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
                    <div className="space-y-3">
                      <div className="flex flex-wrap items-center gap-2">
                        <div className="text-lg font-semibold text-brand-text">{complaint.title}</div>
                        <Badge variant={complaint.status === 'pending' ? 'warning' : complaint.status === 'in_progress' ? 'info' : 'success'}>
                          {complaint.status === 'in_progress' ? 'In Progress' : complaint.status}
                        </Badge>
                      </div>
                      <div className="text-sm text-brand-muted">
                        {complaint.student_name || 'Unknown Student'} • Room {complaint.room_number || 'N/A'}
                      </div>
                      {complaint.description ? <p className="text-sm leading-7 text-brand-muted">{complaint.description}</p> : null}
                    </div>
                    <div className="grid gap-3 sm:grid-cols-2 lg:w-[290px]">
                      <div className="rounded-[22px] border border-white bg-white px-4 py-3">
                        <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Priority</div>
                        <div className="mt-2 text-sm font-semibold uppercase text-brand-text">{complaint.priority || 'Medium'}</div>
                      </div>
                      <div className="rounded-[22px] border border-white bg-white px-4 py-3">
                        <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Created</div>
                        <div className="mt-2 text-sm font-semibold text-brand-text">{format(new Date(complaint.created_at), 'dd MMM yyyy')}</div>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <EmptyState title="No active complaints" description="All service records are clear right now." icon={<Wrench className="h-10 w-10" />} />
          )}
        </PanelShell>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { attendanceAPI } from '../../services/api';
import { Badge, PanelShell, PortalHero, EmptyState, Spinner, Select } from '../../components/ui';
import { format } from 'date-fns';
import { CalendarCheckIcon, Sunrise, Moon, UserCheck } from 'lucide-react';

export default function StudentAttendance() {
  const [records, setRecords] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  
  const currentDate = new Date();
  const [month, setMonth] = useState(currentDate.getMonth() + 1);
  const [year, setYear] = useState(currentDate.getFullYear());

  const fetchAttendance = async () => {
    try {
      setLoading(true);
      const res = await attendanceAPI.getMyAttendance({ month, year });
      setRecords(res.data.data || []);
      setStats(res.data.stats || null);
    } catch (err) {
      toast.error('Failed to load attendance');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAttendance();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [month, year]);

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <PortalHero
        eyebrow="Hostel Records"
        title="My Attendance"
        description="View your bi-daily hostel check-in records and attendance history."
        accent="orange"
        icon={<CalendarCheckIcon className="w-5 h-5" />}
        actions={
          <div className="flex gap-3">
             <Select value={month} onChange={e => setMonth(Number(e.target.value))} className="w-32 bg-white/60">
                {Array.from({length: 12}, (_, i) => (<option key={i+1} value={i+1}>{format(new Date(2000, i, 1), 'MMMM')}</option>))}
             </Select>
             <Select value={year} onChange={e => setYear(Number(e.target.value))} className="w-28 bg-white/60">
                {Array.from({length: 5}, (_, i) => {
                  const y = currentDate.getFullYear() - i;
                  return <option key={y} value={y}>{y}</option>
                })}
             </Select>
          </div>
        }
      />

      {loading ? (
        <div className="flex items-center justify-center py-20"><Spinner size="lg" className="text-orange-500" /></div>
      ) : (
        <>
          {stats && (
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex items-center gap-4">
                 <div className="w-10 h-10 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center shrink-0">
                   <CalendarCheckIcon className="w-5 h-5" />
                 </div>
                 <div>
                    <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider">Days Present</p>
                    <p className="text-2xl font-bold text-gray-900 leading-tight">{stats.days_present || 0}</p>
                 </div>
              </div>
              <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex items-center gap-4">
                 <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center shrink-0">
                   <Sunrise className="w-5 h-5" />
                 </div>
                 <div>
                    <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider">Morning</p>
                    <p className="text-2xl font-bold text-gray-900 leading-tight">{stats.morning_count || 0}</p>
                 </div>
              </div>
              <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex items-center gap-4">
                 <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center shrink-0">
                   <Moon className="w-5 h-5" />
                 </div>
                 <div>
                    <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider">Evening</p>
                    <p className="text-2xl font-bold text-gray-900 leading-tight">{stats.evening_count || 0}</p>
                 </div>
              </div>
              <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex items-center gap-4">
                 <div className="w-10 h-10 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center shrink-0">
                   <UserCheck className="w-5 h-5" />
                 </div>
                 <div>
                    <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider">Total Checks</p>
                    <p className="text-2xl font-bold text-gray-900 leading-tight">{stats.total_checkins || 0}</p>
                 </div>
              </div>
            </div>
          )}

          <PanelShell title={`${format(new Date(year, month - 1, 1), 'MMMM yyyy')} Records`} className="mt-6">
            {records.length > 0 ? (
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-gray-50 text-gray-500 uppercase tracking-wider text-xs">
                    <tr>
                      <th className="px-5 py-4 font-semibold rounded-tl-xl">Date & Time</th>
                      <th className="px-5 py-4 font-semibold">Type</th>
                      <th className="px-5 py-4 font-semibold">Method</th>
                      <th className="px-5 py-4 font-semibold rounded-tr-xl">Marked By</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {records.map(r => (
                      <tr key={r.id} className="hover:bg-gray-50 transition-colors">
                        <td className="px-5 py-4 whitespace-nowrap">
                          <span className="font-semibold text-gray-900 block">{format(new Date(r.checked_at), 'dd MMM yyyy')}</span>
                          <span className="text-gray-500">{format(new Date(r.checked_at), 'hh:mm a')}</span>
                        </td>
                        <td className="px-5 py-4 whitespace-nowrap">
                          {r.check_type === 'morning' ? <Badge variant="primary" className="gap-1"><Sunrise className="w-3 h-3"/> Morning</Badge> : null}
                          {r.check_type === 'evening' ? <Badge variant="purple" className="gap-1"><Moon className="w-3 h-3"/> Evening</Badge> : null}
                          {r.check_type === 'manual'  ? <Badge variant="default" className="gap-1"><UserCheck className="w-3 h-3"/> Manual Check</Badge> : null}
                        </td>
                        <td className="px-5 py-4 whitespace-nowrap">
                           <Badge variant="outline" className="capitalize">{r.method}</Badge>
                        </td>
                        <td className="px-5 py-4 whitespace-nowrap text-gray-600">
                          {r.marked_by_name || 'System / Auto'}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <EmptyState title="No Attendance Records" description="No successful check-ins found for this period." icon={<CalendarCheckIcon className="w-10 h-10 text-gray-300" />} />
            )}
          </PanelShell>
        </>
      )}
    </div>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import toast from 'react-hot-toast';
import { format } from 'date-fns';
import {
  ArrowRight,
  CalendarDays,
  CheckCheck,
  ChevronRight,
  CircleAlert,
  ClipboardList,
  Eye,
  PencilLine,
  SearchCheck,
  Sparkles,
  UserCog,
} from 'lucide-react';
import { studentPortalAPI } from '../../services/api';
import { Badge, Button, EmptyState, Input, Modal, Select, Spinner, Textarea } from '../../components/ui';

const CATEGORY_OPTIONS = ['all', 'plumbing', 'electrical', 'carpentry', 'housekeeping', 'network', 'mess', 'other'];
const PRIORITY_OPTIONS = ['all', 'low', 'medium', 'high'];
const STATUS_OPTIONS = ['all', 'pending', 'in_progress', 'resolved'];

const CATEGORY_META = {
  plumbing: { label: 'Plumbing', desk: 'Maintenance Desk', accent: 'bg-sky-50 text-sky-700 border-sky-100' },
  electrical: { label: 'Electrical', desk: 'Electrical Team', accent: 'bg-violet-50 text-violet-700 border-violet-100' },
  carpentry: { label: 'Carpentry', desk: 'Facility Repairs', accent: 'bg-amber-50 text-amber-700 border-amber-100' },
  housekeeping: { label: 'Housekeeping', desk: 'Housekeeping Crew', accent: 'bg-emerald-50 text-emerald-700 border-emerald-100' },
  network: { label: 'Network', desk: 'IT Support Cell', accent: 'bg-blue-50 text-blue-700 border-blue-100' },
  mess: { label: 'Mess', desk: 'Mess Operations', accent: 'bg-rose-50 text-rose-700 border-rose-100' },
  other: { label: 'General', desk: 'Student Services Desk', accent: 'bg-slate-100 text-slate-700 border-slate-200' },
};

const STATUS_META = {
  pending: { label: 'Pending', badge: 'warning', pill: 'bg-amber-50 text-amber-700 border-amber-100', helper: 'Queued for hostel review' },
  in_progress: { label: 'In Progress', badge: 'info', pill: 'bg-blue-50 text-blue-700 border-blue-100', helper: 'Assigned to a service desk' },
  resolved: { label: 'Resolved', badge: 'success', pill: 'bg-emerald-50 text-emerald-700 border-emerald-100', helper: 'Closed and confirmed' },
};

const PRIORITY_META = {
  low: { label: 'Low', badge: 'success', pill: 'bg-emerald-50 text-emerald-700 border-emerald-100' },
  medium: { label: 'Medium', badge: 'warning', pill: 'bg-amber-50 text-amber-700 border-amber-100' },
  high: { label: 'High', badge: 'danger', pill: 'bg-red-50 text-red-700 border-red-100' },
};

const DEFAULT_FORM = { title: '', description: '', category: 'other', priority: 'medium' };

function toTitleCase(value) {
  return value.replace(/_/g, ' ').replace(/\b\w/g, char => char.toUpperCase());
}

export default function StudentComplaints() {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [editingComplaint, setEditingComplaint] = useState(null);
  const [filters, setFilters] = useState({ status: 'all', category: 'all', priority: 'all' });
  const [form, setForm] = useState(DEFAULT_FORM);

  const loadComplaints = () => {
    setLoading(true);
    studentPortalAPI.getComplaints()
      .then(response => setComplaints(response.data.data || []))
      .catch(() => setComplaints([]))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    loadComplaints();
  }, []);

  const filteredComplaints = useMemo(() => complaints.filter(complaint => (
    (filters.status === 'all' || complaint.status === filters.status) &&
    (filters.category === 'all' || complaint.category === filters.category) &&
    (filters.priority === 'all' || complaint.priority === filters.priority)
  )), [complaints, filters]);

  const complaintStats = useMemo(() => ({
    pending: complaints.filter(complaint => complaint.status === 'pending').length,
    inProgress: complaints.filter(complaint => complaint.status === 'in_progress').length,
    resolved: complaints.filter(complaint => complaint.status === 'resolved').length,
    active: complaints.filter(complaint => complaint.status !== 'resolved').length,
  }), [complaints]);

  const resetFormState = () => {
    setForm(DEFAULT_FORM);
    setEditingComplaint(null);
    setModalOpen(false);
  };

  const openCreateModal = () => {
    setEditingComplaint(null);
    setForm(DEFAULT_FORM);
    setModalOpen(true);
  };

  const openEditModal = complaint => {
    if (complaint.status !== 'pending') {
      toast.error('Only pending complaints can be edited.');
      return;
    }

    setEditingComplaint(complaint);
    setForm({
      title: complaint.title || '',
      description: complaint.description || '',
      category: complaint.category || 'other',
      priority: complaint.priority || 'medium',
    });
    setModalOpen(true);
  };

  const handleSubmit = async () => {
    if (!form.title.trim()) {
      toast.error('Title is required.');
      return;
    }

    setSaving(true);
    try {
      if (editingComplaint) {
        await studentPortalAPI.updateComplaint(editingComplaint.id, form);
        toast.success('Complaint updated successfully.');
      } else {
        await studentPortalAPI.fileComplaint(form);
        toast.success('Complaint filed successfully.');
      }

      resetFormState();
      loadComplaints();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to save complaint.');
    } finally {
      setSaving(false);
    }
  };

  const handleResolve = async complaint => {
    if (complaint.status === 'resolved') return;

    try {
      await studentPortalAPI.resolveComplaint(complaint.id);
      toast.success('Complaint marked as resolved.');
      if (selectedComplaint?.id === complaint.id) {
        setSelectedComplaint(current => current ? { ...current, status: 'resolved' } : current);
      }
      loadComplaints();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to resolve complaint.');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <section className="relative overflow-hidden rounded-[36px] border border-white/70 bg-white/80 px-6 py-7 shadow-[0_28px_60px_rgba(145,158,171,0.14)] backdrop-blur-xl md:px-8 md:py-9">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_left,rgba(159,116,247,0.14),transparent_30%),radial-gradient(circle_at_bottom_right,rgba(3,136,252,0.08),transparent_24%)]" />
        <div className="absolute -right-20 -top-20 h-56 w-56 rounded-full bg-brand-primary/10 blur-3xl" />
        <div className="absolute bottom-0 left-1/3 h-40 w-40 rounded-full bg-[#dbe7ff] blur-3xl" />

        <div className="relative flex flex-col gap-8 xl:flex-row xl:items-start xl:justify-between">
          <div className="max-w-3xl">
            <div className="inline-flex items-center gap-2 rounded-full bg-[#f4f1ff] px-4 py-2 text-[11px] font-semibold uppercase tracking-[0.24em] text-brand-primary">
              <Sparkles className="h-3.5 w-3.5" strokeWidth={2} />
              Student Services Desk
            </div>
            <h1 className="mt-6 max-w-2xl font-display text-4xl font-black tracking-[-0.04em] text-brand-text md:text-[3.55rem] md:leading-[1.04]">
              Complaints and Service Requests
            </h1>
            <p className="mt-5 max-w-3xl text-base leading-8 text-brand-muted md:text-[1.15rem]">
              Track maintenance issues, grievance requests, room concerns, and service-desk responses from one premium resident portal.
            </p>
            <div className="mt-7 inline-flex items-center gap-3 rounded-full border border-[#ece8ff] bg-[#f8f6ff] px-4 py-3 text-[11px] font-semibold uppercase tracking-[0.18em] text-[#5d5f90]">
              <SearchCheck className="h-4 w-4 text-brand-primary" strokeWidth={2} />
              {complaintStats.active} Active Records
            </div>
          </div>

          <div className="flex w-full flex-col gap-4 xl:max-w-sm xl:items-end">
            <Button
              onClick={openCreateModal}
              className="h-14 rounded-[20px] px-6 text-base shadow-[0_18px_42px_rgba(125,83,246,0.24)]"
            >
              File Complaint
              <ArrowRight className="h-4 w-4" strokeWidth={2} />
            </Button>

            <div className="w-full rounded-[28px] border border-[#ece8ff] bg-[linear-gradient(180deg,rgba(250,248,255,0.95)_0%,rgba(244,247,255,0.92)_100%)] p-5 shadow-sm xl:max-w-[310px]">
              <div className="flex items-start justify-between gap-4">
                <div>
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-muted">Service Summary</div>
                  <div className="mt-2 text-2xl font-black text-brand-text">{filteredComplaints.length}</div>
                  <div className="mt-1 text-sm text-brand-muted">Visible requests after filters</div>
                </div>
                <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-brand-primary/10 text-brand-primary">
                  <ClipboardList className="h-5 w-5" strokeWidth={2} />
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="grid gap-4 md:grid-cols-3">
        {[
          { label: 'Pending', value: complaintStats.pending, tone: 'bg-amber-50 text-amber-700 border-amber-100' },
          { label: 'In Progress', value: complaintStats.inProgress, tone: 'bg-blue-50 text-blue-700 border-blue-100' },
          { label: 'Resolved', value: complaintStats.resolved, tone: 'bg-emerald-50 text-emerald-700 border-emerald-100' },
        ].map(item => (
          <div
            key={item.label}
            className="rounded-[32px] border border-white/80 bg-white/85 px-6 py-7 text-center shadow-[0_20px_48px_rgba(145,158,171,0.12)] backdrop-blur-xl"
          >
            <div className="mx-auto mb-5 flex h-12 w-12 items-center justify-center rounded-2xl bg-[#f7f8fd] text-brand-primary">
              <CircleAlert className="h-5 w-5" strokeWidth={1.9} />
            </div>
            <div className="font-display text-4xl font-black tracking-[-0.04em] text-brand-text">{item.value}</div>
            <div className="mt-2 text-[13px] font-semibold uppercase tracking-[0.2em] text-brand-muted">{item.label}</div>
            <div className={`mx-auto mt-5 inline-flex rounded-full border px-3 py-1 text-[11px] font-semibold uppercase tracking-[0.12em] ${item.tone}`}>
              Updated live
            </div>
          </div>
        ))}
      </section>

      <section className="overflow-hidden rounded-[36px] border border-white/80 bg-white/85 shadow-[0_24px_60px_rgba(145,158,171,0.14)] backdrop-blur-xl">
        <div className="bg-[linear-gradient(180deg,rgba(247,248,253,0.95)_0%,rgba(247,248,253,0.75)_100%)] px-6 py-6 md:px-8 md:py-7">
          <h2 className="font-display text-[2rem] font-bold tracking-[-0.04em] text-brand-text">Service Filters</h2>
          <p className="mt-2 max-w-2xl text-sm leading-7 text-brand-muted md:text-base">
            Narrow requests by workflow status, complaint category, and urgency to review the exact service tickets you need.
          </p>
        </div>

        <div className="border-t border-brand-border/70 px-6 py-6 md:px-8">
          <div className="grid gap-4 md:grid-cols-3">
            <Select
              value={filters.status}
              onChange={event => setFilters(current => ({ ...current, status: event.target.value }))}
              className="h-14 rounded-[20px] border-brand-border/80 bg-[#fbfbff] px-5 text-base"
            >
              {STATUS_OPTIONS.map(option => (
                <option key={option} value={option}>
                  {option === 'all' ? 'All Status' : toTitleCase(option)}
                </option>
              ))}
            </Select>

            <Select
              value={filters.category}
              onChange={event => setFilters(current => ({ ...current, category: event.target.value }))}
              className="h-14 rounded-[20px] border-brand-border/80 bg-[#fbfbff] px-5 text-base"
            >
              {CATEGORY_OPTIONS.map(option => (
                <option key={option} value={option}>
                  {option === 'all' ? 'All Categories' : CATEGORY_META[option]?.label || toTitleCase(option)}
                </option>
              ))}
            </Select>

            <Select
              value={filters.priority}
              onChange={event => setFilters(current => ({ ...current, priority: event.target.value }))}
              className="h-14 rounded-[20px] border-brand-border/80 bg-[#fbfbff] px-5 text-base"
            >
              {PRIORITY_OPTIONS.map(option => (
                <option key={option} value={option}>
                  {option === 'all' ? 'All Priority' : toTitleCase(option)}
                </option>
              ))}
            </Select>
          </div>
        </div>
      </section>

      <section className="rounded-[36px] border border-white/80 bg-[linear-gradient(180deg,rgba(247,248,253,0.72)_0%,rgba(255,255,255,0.84)_100%)] p-4 shadow-[0_24px_60px_rgba(145,158,171,0.12)] backdrop-blur-xl md:p-5">
        <div className="mb-4 flex flex-col gap-3 px-2 pt-2 md:flex-row md:items-center md:justify-between">
          <div>
            <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-primary">Resident Queue</div>
            <h2 className="mt-2 font-display text-[1.9rem] font-bold tracking-[-0.04em] text-brand-text">Open Requests</h2>
          </div>
          <div className="rounded-full border border-brand-border/70 bg-white/90 px-4 py-2 text-sm font-medium text-brand-muted">
            {filteredComplaints.length} request{filteredComplaints.length === 1 ? '' : 's'} found
          </div>
        </div>

        {loading ? (
          <div className="flex justify-center py-20">
            <Spinner size="lg" className="text-brand-primary" />
          </div>
        ) : filteredComplaints.length === 0 ? (
          <div className="rounded-[28px] bg-white/80 px-4 py-10">
            <EmptyState
              title="No complaints match the selected filters"
              description="Try adjusting the workflow, category, or priority filters to see more service records."
            />
          </div>
        ) : (
          <div className="space-y-4">
            {filteredComplaints.map((complaint, index) => {
              const categoryMeta = CATEGORY_META[complaint.category] || CATEGORY_META.other;
              const statusMeta = STATUS_META[complaint.status] || STATUS_META.pending;
              const priorityMeta = PRIORITY_META[complaint.priority] || PRIORITY_META.medium;
              const canEdit = complaint.status === 'pending';
              const canResolve = complaint.status !== 'resolved';

              return (
                <motion.article
                  key={complaint.id}
                  initial={{ opacity: 0, y: 16 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.04 }}
                  className="group rounded-[30px] border border-white/90 bg-white/88 p-5 shadow-[0_22px_54px_rgba(145,158,171,0.12)] transition-all duration-300 hover:-translate-y-0.5 hover:shadow-[0_30px_70px_rgba(145,158,171,0.16)] md:p-6"
                >
                  <div className="flex flex-col gap-5 xl:flex-row xl:items-start xl:justify-between">
                    <div className="min-w-0 flex-1">
                      <div className="flex flex-col gap-4 md:flex-row md:items-start md:gap-5">
                        <div className={`flex h-14 w-14 flex-shrink-0 items-center justify-center rounded-[20px] border ${categoryMeta.accent}`}>
                          <ClipboardList className="h-5 w-5" strokeWidth={1.9} />
                        </div>

                        <div className="min-w-0 flex-1">
                          <div className="flex flex-wrap items-center gap-2.5">
                            <h3 className="font-display text-[1.45rem] font-bold tracking-[-0.03em] text-brand-text">
                              {complaint.title}
                            </h3>
                            <Badge variant={statusMeta.badge}>{statusMeta.label}</Badge>
                            <Badge variant={priorityMeta.badge}>{priorityMeta.label} Priority</Badge>
                          </div>

                          <div className="mt-3 flex flex-wrap items-center gap-2 text-xs font-semibold uppercase tracking-[0.14em] text-brand-muted">
                            <span className={`inline-flex rounded-full border px-3 py-1 ${categoryMeta.accent}`}>
                              {categoryMeta.label}
                            </span>
                            <span className={`inline-flex rounded-full border px-3 py-1 ${statusMeta.pill}`}>
                              {statusMeta.helper}
                            </span>
                          </div>

                          <p className="mt-4 max-w-4xl text-sm leading-7 text-brand-muted md:text-[15px]">
                            {complaint.description || 'No additional description provided for this service request.'}
                          </p>

                          <div className="mt-5 grid gap-3 sm:grid-cols-2 xl:grid-cols-4">
                            <div className="rounded-[22px] border border-brand-border/60 bg-[#fafbff] px-4 py-3">
                              <div className="flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">
                                <CalendarDays className="h-3.5 w-3.5 text-brand-primary" strokeWidth={2} />
                                Created
                              </div>
                              <div className="mt-2 text-sm font-semibold text-brand-text">
                                {format(new Date(complaint.created_at), 'dd MMM yyyy')}
                              </div>
                            </div>

                            <div className="rounded-[22px] border border-brand-border/60 bg-[#fafbff] px-4 py-3">
                              <div className="flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">
                                <UserCog className="h-3.5 w-3.5 text-brand-primary" strokeWidth={2} />
                                Assigned Desk
                              </div>
                              <div className="mt-2 text-sm font-semibold text-brand-text">{categoryMeta.desk}</div>
                            </div>

                            <div className="rounded-[22px] border border-brand-border/60 bg-[#fafbff] px-4 py-3">
                              <div className="flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">
                                <ChevronRight className="h-3.5 w-3.5 text-brand-primary" strokeWidth={2} />
                                Room
                              </div>
                              <div className="mt-2 text-sm font-semibold text-brand-text">
                                {complaint.room_number ? `Room ${complaint.room_number}` : 'Resident record'}
                              </div>
                            </div>

                            <div className="rounded-[22px] border border-brand-border/60 bg-[#fafbff] px-4 py-3">
                              <div className="flex items-center gap-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">
                                <CheckCheck className="h-3.5 w-3.5 text-brand-primary" strokeWidth={2} />
                                Updated
                              </div>
                              <div className="mt-2 text-sm font-semibold text-brand-text">
                                {format(new Date(complaint.updated_at || complaint.created_at), 'dd MMM yyyy')}
                              </div>
                            </div>
                          </div>

                          {complaint.admin_note ? (
                            <div className="mt-5 rounded-[22px] border border-[#ece8ff] bg-[#f8f6ff] px-4 py-4">
                              <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-primary">Admin Note</div>
                              <p className="mt-2 text-sm leading-7 text-brand-muted">{complaint.admin_note}</p>
                            </div>
                          ) : null}
                        </div>
                      </div>
                    </div>

                    <div className="flex flex-wrap items-center gap-2 xl:w-[240px] xl:justify-end">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setSelectedComplaint(complaint)}
                        className="h-11 rounded-[18px] px-4"
                      >
                        <Eye className="h-4 w-4" strokeWidth={1.9} />
                        View
                      </Button>

                      <Button
                        variant="outline"
                        size="sm"
                        disabled={!canEdit}
                        onClick={() => openEditModal(complaint)}
                        className="h-11 rounded-[18px] px-4 disabled:opacity-45"
                      >
                        <PencilLine className="h-4 w-4" strokeWidth={1.9} />
                        Edit
                      </Button>

                      <Button
                        size="sm"
                        disabled={!canResolve}
                        onClick={() => handleResolve(complaint)}
                        className="h-11 rounded-[18px] px-4 disabled:opacity-45"
                      >
                        <CheckCheck className="h-4 w-4" strokeWidth={1.9} />
                        {canResolve ? 'Resolve' : 'Resolved'}
                      </Button>
                    </div>
                  </div>
                </motion.article>
              );
            })}
          </div>
        )}
      </section>

      <Modal
        open={modalOpen}
        onClose={resetFormState}
        title={editingComplaint ? 'Edit Complaint' : 'File New Complaint'}
        size="lg"
      >
        <div className="grid gap-5 md:grid-cols-2">
          <div className="md:col-span-2">
            <Input
              label="Complaint Title"
              value={form.title}
              onChange={event => setForm(current => ({ ...current, title: event.target.value }))}
              placeholder="Briefly describe the issue"
              className="h-16 rounded-[24px] bg-[#fbfbff] px-6 text-base"
            />
          </div>

          <div>
            <Select
              label="Category"
              value={form.category}
              onChange={event => setForm(current => ({ ...current, category: event.target.value }))}
              className="h-16 rounded-[24px] bg-[#fbfbff] px-6 text-base"
            >
              {CATEGORY_OPTIONS.filter(option => option !== 'all').map(option => (
                <option key={option} value={option}>
                  {CATEGORY_META[option]?.label || toTitleCase(option)}
                </option>
              ))}
            </Select>
          </div>

          <div>
            <Select
              label="Priority"
              value={form.priority}
              onChange={event => setForm(current => ({ ...current, priority: event.target.value }))}
              className="h-16 rounded-[24px] bg-[#fbfbff] px-6 text-base"
            >
              {PRIORITY_OPTIONS.filter(option => option !== 'all').map(option => (
                <option key={option} value={option}>
                  {toTitleCase(option)}
                </option>
              ))}
            </Select>
          </div>

          <div className="md:col-span-2">
            <Textarea
              label="Description"
              value={form.description}
              onChange={event => setForm(current => ({ ...current, description: event.target.value }))}
              placeholder="Add room details, issue severity, or any other context for the hostel team."
              className="min-h-[150px] rounded-[24px] bg-[#fbfbff] px-6 py-5 text-base"
            />
          </div>

          <div className="flex flex-col-reverse gap-3 pt-1 md:col-span-2 sm:flex-row sm:justify-end">
            <Button
              variant="outline"
              onClick={resetFormState}
              className="h-14 rounded-[20px] px-6 text-base"
            >
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              loading={saving}
              className="h-14 rounded-[20px] px-6 text-base"
            >
              {editingComplaint ? 'Save Changes' : 'File Complaint'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal
        open={Boolean(selectedComplaint)}
        onClose={() => setSelectedComplaint(null)}
        title="Complaint Details"
        size="lg"
      >
        {selectedComplaint ? (
          <div className="space-y-5">
            <div className="flex flex-wrap items-center gap-2">
              <Badge variant={(STATUS_META[selectedComplaint.status] || STATUS_META.pending).badge}>
                {(STATUS_META[selectedComplaint.status] || STATUS_META.pending).label}
              </Badge>
              <Badge variant={(PRIORITY_META[selectedComplaint.priority] || PRIORITY_META.medium).badge}>
                {(PRIORITY_META[selectedComplaint.priority] || PRIORITY_META.medium).label} Priority
              </Badge>
              <Badge variant="default">
                {(CATEGORY_META[selectedComplaint.category] || CATEGORY_META.other).label}
              </Badge>
            </div>

            <div>
              <h3 className="font-display text-2xl font-bold text-brand-text">{selectedComplaint.title}</h3>
              <p className="mt-3 text-sm leading-7 text-brand-muted">
                {selectedComplaint.description || 'No additional description was attached to this complaint.'}
              </p>
            </div>

            <div className="grid gap-3 md:grid-cols-2">
              <div className="rounded-[22px] border border-brand-border/70 bg-[#fafbff] px-4 py-4">
                <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Created On</div>
                <div className="mt-2 text-sm font-semibold text-brand-text">
                  {format(new Date(selectedComplaint.created_at), 'dd MMM yyyy, hh:mm a')}
                </div>
              </div>

              <div className="rounded-[22px] border border-brand-border/70 bg-[#fafbff] px-4 py-4">
                <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Assigned Desk</div>
                <div className="mt-2 text-sm font-semibold text-brand-text">
                  {(CATEGORY_META[selectedComplaint.category] || CATEGORY_META.other).desk}
                </div>
              </div>
            </div>

            {selectedComplaint.admin_note ? (
              <div className="rounded-[24px] border border-[#ece8ff] bg-[#f8f6ff] px-5 py-5">
                <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-primary">Admin Note</div>
                <p className="mt-2 text-sm leading-7 text-brand-muted">{selectedComplaint.admin_note}</p>
              </div>
            ) : null}
          </div>
        ) : null}
      </Modal>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { AlertCircle, CheckCircle2, Clock, MapPin, Sparkles } from 'lucide-react';
import { studentPortalAPI } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { Badge, Button, EmptyState, MetricPanel, PanelShell, PortalHero, Spinner } from '../../components/ui';

export default function StudentDashboardPortal() {
  const { user } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    studentPortalAPI.getDashboard()
      .then(response => setData(response.data.data))
      .catch(() => setData({ student: null, roommates: [], complaintStats: {}, recentNotices: [] }))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="flex min-h-[60vh] items-center justify-center">
        <Spinner size="lg" className="text-brand-primary" />
      </div>
    );
  }

  const { student, roommates = [], complaintStats = {}, recentNotices = [] } = data || {};

  return (
    <div className="space-y-6">
      <PortalHero
        eyebrow="Student Portal"
        title={`Welcome back, ${user?.name || 'Resident'}`}
        description="Review room allocation, roommate details, service requests, and latest hostel updates from one unified dashboard."
        accent="primary"
        icon={<Sparkles className="h-4 w-4" />}
        actions={
          <>
            <Link to="/student/complaints">
              <Button className="h-12 rounded-[18px] px-5">File Complaint</Button>
            </Link>
            <Link to="/student/profile">
              <Button variant="outline" className="h-12 rounded-[18px] px-5">View Profile</Button>
            </Link>
          </>
        }
      />

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <MetricPanel title="Total Complaints" value={complaintStats?.total || 0} helper="All submitted requests" icon={<AlertCircle className="h-5 w-5" />} />
        <MetricPanel title="Pending" value={complaintStats?.pending || 0} helper="Awaiting review" tone="orange" icon={<Clock className="h-5 w-5" />} />
        <MetricPanel title="In Progress" value={complaintStats?.in_progress || 0} helper="Assigned to hostel team" tone="blue" icon={<MapPin className="h-5 w-5" />} />
        <MetricPanel title="Resolved" value={complaintStats?.resolved || 0} helper="Closed requests" tone="green" icon={<CheckCircle2 className="h-5 w-5" />} />
      </div>

      <div className="grid gap-6 xl:grid-cols-[1.55fr_1fr]">
        <PanelShell
          title="Room Overview"
          description="Current allocation details and the residents sharing your room."
          action={student?.room_number ? <Badge variant="success">Assigned</Badge> : <Badge variant="warning">Pending Allocation</Badge>}
        >
          {student?.room_number ? (
            <div className="space-y-6">
              <div className="grid gap-4 md:grid-cols-3">
                <div className="rounded-[28px] bg-gradient-to-br from-brand-primary to-[#7e57c2] p-6 text-white shadow-lg">
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-white/80">Room Number</div>
                  <div className="mt-3 font-display text-5xl font-black tracking-[-0.04em]">{student.room_number}</div>
                </div>
                <div className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-6">
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-muted">Block</div>
                  <div className="mt-3 font-display text-4xl font-black tracking-[-0.04em] text-brand-text">{student.block}</div>
                </div>
                <div className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-6">
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-muted">Floor</div>
                  <div className="mt-3 font-display text-4xl font-black tracking-[-0.04em] text-brand-text">{student.floor}</div>
                </div>
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="rounded-[24px] border border-brand-border/70 bg-[#fafbff] px-5 py-4">
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-muted">Room Type</div>
                  <div className="mt-2 text-base font-semibold capitalize text-brand-text">{student.room_type || 'Standard'}</div>
                </div>
                <div className="rounded-[24px] border border-brand-border/70 bg-[#fafbff] px-5 py-4">
                  <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-muted">Warden</div>
                  <div className="mt-2 text-base font-semibold text-brand-text">{student.warden_name || 'Head Warden'}</div>
                </div>
              </div>

              <div>
                <div className="mb-4 text-[11px] font-semibold uppercase tracking-[0.18em] text-brand-primary">Roommates</div>
                {roommates.length > 0 ? (
                  <div className="grid gap-4 md:grid-cols-2">
                    {roommates.map(roommate => (
                      <div key={roommate.id || roommate.register_no} className="flex items-center gap-4 rounded-[26px] border border-brand-border/70 bg-white px-4 py-4 shadow-sm">
                        <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-gradient-to-br from-brand-primary to-[#7e57c2] text-sm font-bold text-white">
                          {roommate.name?.charAt(0)?.toUpperCase()}
                        </div>
                        <div className="min-w-0">
                          <div className="truncate text-base font-semibold text-brand-text">{roommate.name}</div>
                          <div className="mt-1 text-sm text-brand-muted">{roommate.department} • Year {roommate.year}</div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <EmptyState title="No roommate details available" description="Roommate information will appear here when the hostel records are updated." />
                )}
              </div>
            </div>
          ) : (
            <div className="rounded-[28px] border border-dashed border-gray-300 bg-[#fafbff] px-6 py-12">
              <EmptyState title="No room allocated yet" description="Please contact the hostel administration for your room assignment details." icon={<AlertCircle className="h-10 w-10" />} />
            </div>
          )}
        </PanelShell>

        <PanelShell
          title="Recent Notices"
          description="Latest hostel communication relevant to students."
          action={<Link to="/student/notices" className="text-sm font-semibold text-brand-primary">View all</Link>}
        >
          {recentNotices.length > 0 ? (
            <div className="space-y-4">
              {recentNotices.map(notice => (
                <div key={notice.id} className="rounded-[24px] border border-brand-border/70 bg-[#fafbff] px-5 py-4">
                  <div className="flex flex-wrap items-center gap-2">
                    <div className="text-base font-semibold text-brand-text">{notice.title}</div>
                    {notice.category === 'urgent' ? <Badge variant="danger">Urgent</Badge> : null}
                  </div>
                  {notice.content ? <p className="mt-3 text-sm leading-7 text-brand-muted">{notice.content}</p> : null}
                  <div className="mt-4 text-xs font-medium uppercase tracking-[0.14em] text-brand-muted">
                    {format(new Date(notice.created_at), 'dd MMM yyyy')}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <EmptyState title="No new notices" description="You're all caught up for now." icon={<CheckCircle2 className="h-10 w-10" />} />
          )}
        </PanelShell>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { hostelApplicationsAPI } from '../../services/api';
import { Badge, Button, Select, Textarea, PanelShell, PortalHero, EmptyState, Spinner } from '../../components/ui';
import { format } from 'date-fns';
import { BuildingIcon, FileTextIcon, CheckCircle2, Clock, XCircle } from 'lucide-react';

export default function StudentHostelApplication() {
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [academicYear, setAcademicYear] = useState('2025-2026');
  const [semester, setSemester] = useState(1);
  const [preferredBlock, setPreferredBlock] = useState('');
  const [preferredRoomType, setPreferredRoomType] = useState('3');
  const [reason, setReason] = useState('');

  const fetchApplications = async () => {
    try {
      setLoading(true);
      const res = await hostelApplicationsAPI.getMyApplications();
      setApplications(res.data.data || []);
      const hasPending = (res.data.data || []).some(a => a.status === 'pending');
      if (!hasPending && (res.data.data || []).length === 0) {
        setShowForm(true);
      } else {
        setShowForm(false);
      }
    } catch (err) {
      toast.error('Failed to load applications');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchApplications();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setSubmitting(true);
      await hostelApplicationsAPI.create({
        academic_year: academicYear,
        semester: Number(semester),
        preferred_block: preferredBlock || null,
        preferred_room_type: preferredRoomType || null,
        reason
      });
      toast.success('Application submitted successfully!');
      setReason('');
      fetchApplications();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to submit application');
    } finally {
      setSubmitting(false);
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'approved': return <Badge variant="success" className="flex items-center gap-1"><CheckCircle2 className="w-3 h-3"/> Approved</Badge>;
      case 'rejected': return <Badge variant="danger" className="flex items-center gap-1"><XCircle className="w-3 h-3"/> Rejected</Badge>;
      default: return <Badge variant="warning" className="flex items-center gap-1"><Clock className="w-3 h-3"/> Pending</Badge>;
    }
  };

  if (loading) {
    return <div className="flex items-center justify-center min-h-[50vh]"><Spinner size="lg" className="text-brand-primary" /></div>;
  }

  const hasPending = applications.some(a => a.status === 'pending');

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <PortalHero
        eyebrow="Hostel Accommodation"
        title="Hostel Application"
        description="Apply for a hostel room for the upcoming academic year. View your application status and history."
        accent="primary"
        icon={<BuildingIcon className="w-5 w-5" />}
        actions={
          !hasPending && !showForm && (
            <Button onClick={() => setShowForm(true)} className="rounded-xl px-6">
              New Application
            </Button>
          )
        }
      />

      {showForm && !hasPending && (
        <PanelShell title="New Hostel Application" description="Submit your preferences for the upcoming academic year.">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
              <Select label="Academic Year" value={academicYear} onChange={e => setAcademicYear(e.target.value)} required>
                <option value="2024-2025">2024-2025</option>
                <option value="2025-2026">2025-2026</option>
                <option value="2026-2027">2026-2027</option>
              </Select>
              <Select label="Year of Study" value={semester} onChange={e => setSemester(e.target.value)} required>
                <option value={1}>1st Year</option>
                <option value={2}>2nd Year</option>
                <option value={3}>3rd Year</option>
                <option value={4}>4th Year</option>
              </Select>
              <Select label="Preferred Block (Optional)" value={preferredBlock} onChange={e => setPreferredBlock(e.target.value)}>
                <option value="">No Preference</option>
                <option value="A">Block A</option>
                <option value="B">Block B</option>
                <option value="C">Block C</option>
                <option value="D">Block D</option>
              </Select>
              <Select label="Preferred Room Type" value={preferredRoomType} onChange={e => setPreferredRoomType(e.target.value)}>
                <option value="1">1 Cot</option>
                <option value="2">2 Cot</option>
                <option value="3">3 Cot</option>
                <option value="4">4 Cot</option>
              </Select>
            </div>

            <div className="flex items-center justify-end gap-3 pt-4 border-t border-gray-100">
              {applications.length > 0 && (
                <Button type="button" variant="outline" onClick={() => setShowForm(false)}>Cancel</Button>
              )}
              <Button type="submit" loading={submitting}>Submit Application</Button>
            </div>
          </form>
        </PanelShell>
      )}

      {applications.length > 0 && !showForm && (
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider pl-1 font-display">Your Applications</h3>
          {applications.map(app => (
            <PanelShell key={app.id} className="transition-all hover:border-brand-primary/30">
              <div className="flex flex-col sm:flex-row justify-between gap-4">
                <div className="space-y-3">
                  <div className="flex items-center gap-3">
                    <span className="font-bold text-lg text-gray-900">{app.academic_year}</span>
                    <Badge variant="outline">Year {app.semester}</Badge>
                    {getStatusBadge(app.status)}
                  </div>
                  
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-y-2 gap-x-8 text-sm">
                    <div>
                      <span className="text-gray-500 text-xs uppercase tracking-wider font-medium block mb-1">Block Pref</span>
                      <span className="text-gray-900 font-medium">{app.preferred_block || 'Any'}</span>
                    </div>
                    <div>
                      <span className="text-gray-500 text-xs uppercase tracking-wider font-medium block mb-1">Room Pref</span>
                      <span className="text-gray-900 font-medium capitalize">{app.preferred_room_type ? `${app.preferred_room_type} Cot` : 'Any'}</span>
                    </div>
                    <div>
                      <span className="text-gray-500 text-xs uppercase tracking-wider font-medium block mb-1">Applied On</span>
                      <span className="text-gray-900 font-medium">{format(new Date(app.created_at), 'dd MMM yyyy')}</span>
                    </div>
                  </div>

                  {app.reason && (
                    <div className="mt-4 pt-3 border-t border-gray-50">
                       <span className="text-gray-500 text-xs uppercase tracking-wider font-medium block mb-1">Note</span>
                       <p className="text-gray-700 text-sm leading-relaxed">{app.reason}</p>
                    </div>
                  )}

                  {app.status !== 'pending' && app.review_note && (
                    <div className={`mt-2 p-3 rounded-xl border flex gap-3 items-start text-sm ${app.status === 'approved' ? 'bg-emerald-50 border-emerald-100 text-emerald-800' : 'bg-red-50 border-red-100 text-red-800'}`}>
                      <FileTextIcon className={`w-4 h-4 mt-0.5 shrink-0 ${app.status === 'approved' ? 'text-emerald-500' : 'text-red-500'}`} />
                      <div>
                        <span className="font-semibold block mb-0.5">Warden Note:</span>
                        <p>{app.review_note}</p>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </PanelShell>
          ))}
        </div>
      )}

      {applications.length === 0 && !showForm && (
        <EmptyState 
           title="No Applications Found" 
           description="You haven't applied for a hostel room yet. Click 'New Application' to get started." 
           icon={<BuildingIcon className="w-12 h-12 text-gray-300" />} 
        />
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { leavesAPI } from '../../services/api';
import { Card, Button, Input, Badge, Table, Modal, Spinner } from '../../components/ui';
import { Plus, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';

export default function StudentLeaveRequest() {
  const { user } = useAuth();
  const [leaves, setLeaves] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [submitLoading, setSubmitLoading] = useState(false);
  
  const [formData, setFormData] = useState({
    from_date: '',
    to_date: '',
    reason: ''
  });

  const fetchLeaves = async () => {
    try {
      setLoading(true);
      // Backend automatically checks the currently logged-in student, but we can pass student_id if our schema binds it.
      // Wait, in studentPortal we usually fetch based on req.user.id but leaveCtrl is generic.
      // We will pass student_id to getAll filter.
      const res = await leavesAPI.getAll({ student_id: user.student_id });
      setLeaves(res.data.data);
    } catch (err) {
      toast.error('Failed to load leave history');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user && user.student_id) {
       fetchLeaves();
    } else if (user) {
       // User exists but has no linked student profile — stop the spinner
       setLoading(false);
    }
    // eslint-disable-next-line
  }, [user]);

  const handleCreate = async (e) => {
    e.preventDefault();
    if (!user.student_id) return toast.error('Student profile not linked. Cannot request leave.');
    
    try {
      setSubmitLoading(true);
      await leavesAPI.create({ ...formData, student_id: user.student_id });
      toast.success('Leave request submitted');
      setIsModalOpen(false);
      setFormData({ from_date: '', to_date: '', reason: '' });
      fetchLeaves();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to submit request');
    } finally {
      setSubmitLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this pending request?')) return;
    try {
      await leavesAPI.delete(id);
      toast.success('Request deleted');
      fetchLeaves();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete request');
    }
  };

  const getStatusBadge = (status) => {
    const map = { pending: 'warning', approved: 'success', rejected: 'danger' };
    return <Badge variant={map[status]}>{status.charAt(0).toUpperCase() + status.slice(1)}</Badge>;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Outpass / Leave Request</h1>
          <p className="text-sm text-gray-500 mt-1">Request permission to leave the hostel</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2">
          <Plus className="h-4 w-4" />
          Apply for Leave
        </Button>
      </div>

      <Card className="p-4">
        <h2 className="text-lg font-bold mb-4">Leave History</h2>
        {loading ? (
          <div className="py-12 flex justify-center"><Spinner /></div>
        ) : (
          <div className="overflow-x-auto">
            <Table 
              columns={[
                { key: 'from_date', label: 'From Date', render: (val) => new Date(val).toLocaleDateString() },
                { key: 'to_date', label: 'To Date', render: (val) => new Date(val).toLocaleDateString() },
                { key: 'duration', label: 'Duration', render: (_, row) => `${Math.ceil((new Date(row.to_date) - new Date(row.from_date)) / (1000 * 60 * 60 * 24)) + 1} Day(s)` },
                { key: 'reason', label: 'Reason', render: (val) => <div className="max-w-xs truncate" title={val}>{val}</div> },
                { key: 'status', label: 'Status', render: (val) => getStatusBadge(val) },
                { key: 'actions', label: 'Actions', render: (_, row) => (
                  row.status === 'pending' ? (
                    <Button size="sm" variant="outline" onClick={() => handleDelete(row.id)} className="text-red-600 border-red-200">
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  ) : null
                )}
              ]}
              data={leaves} 
            />
          </div>
        )}
      </Card>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Apply for Outpass">
        <form onSubmit={handleCreate} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <Input 
              type="date"
              label="From Date" 
              required 
              value={formData.from_date} 
              onChange={e => setFormData({...formData, from_date: e.target.value})} 
            />
            <Input 
              type="date"
              label="To Date" 
              required 
              value={formData.to_date} 
              onChange={e => setFormData({...formData, to_date: e.target.value})} 
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Reason for Leave</label>
            <textarea
              required
              className="w-full rounded-xl border-gray-300 shadow-sm focus:border-brand-primary focus:ring-brand-primary min-h-[100px] p-3 border"
              placeholder="Provide a valid reason for your leave request..."
              value={formData.reason}
              onChange={e => setFormData({...formData, reason: e.target.value})}
            />
          </div>
          <div className="flex justify-end gap-3 mt-6">
            <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            <Button type="submit" disabled={submitLoading}>
              {submitLoading ? 'Submitting...' : 'Submit Request'}
            </Button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import toast from 'react-hot-toast';
import { CalendarClock, ClipboardCheck, Plus, Trash2 } from 'lucide-react';
import { leavesAPI } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { Badge, Button, EmptyState, Input, MetricPanel, Modal, PanelShell, PortalHero, Spinner, Textarea } from '../../components/ui';

export default function StudentLeaveRequestPortal() {
  const { user } = useAuth();
  const [leaves, setLeaves] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [submitLoading, setSubmitLoading] = useState(false);
  const [formData, setFormData] = useState({ from_date: '', to_date: '', reason: '' });

  const fetchLeaves = useCallback(async () => {
    try {
      setLoading(true);
      const response = await leavesAPI.getAll({ student_id: user.student_id });
      setLeaves(response.data.data || []);
    } catch (error) {
      toast.error('Failed to load leave history');
      setLeaves([]);
    } finally {
      setLoading(false);
    }
  }, [user?.student_id]);

  useEffect(() => {
    if (user?.student_id) {
      fetchLeaves();
    } else if (user) {
      setLoading(false);
    }
  }, [fetchLeaves, user]);

  const stats = useMemo(() => ({
    total: leaves.length,
    pending: leaves.filter(item => item.status === 'pending').length,
    approved: leaves.filter(item => item.status === 'approved').length,
  }), [leaves]);

  const handleCreate = async event => {
    event.preventDefault();
    if (!user?.student_id) {
      toast.error('Student profile not linked. Cannot request leave.');
      return;
    }

    try {
      setSubmitLoading(true);
      await leavesAPI.create({ ...formData, student_id: user.student_id });
      toast.success('Leave request submitted');
      setIsModalOpen(false);
      setFormData({ from_date: '', to_date: '', reason: '' });
      fetchLeaves();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to submit request');
    } finally {
      setSubmitLoading(false);
    }
  };

  const handleDelete = async id => {
    if (!window.confirm('Are you sure you want to delete this pending request?')) return;
    try {
      await leavesAPI.delete(id);
      toast.success('Request deleted');
      fetchLeaves();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete request');
    }
  };

  const statusVariant = status => ({
    pending: 'warning',
    approved: 'success',
    rejected: 'danger',
  }[status] || 'default');

  return (
    <div className="space-y-6">
      <PortalHero
        eyebrow="Student Outpass"
        title="Leave Requests"
        description="Plan out-of-campus movement, submit leave dates, and keep track of approval status from a single student workflow."
        accent="primary"
        icon={<CalendarClock className="h-4 w-4" />}
        actions={<Button onClick={() => setIsModalOpen(true)} className="h-12 rounded-[18px] px-5"><Plus className="h-4 w-4" /> Apply for Leave</Button>}
      />

      <div className="grid gap-4 md:grid-cols-3">
        <MetricPanel title="Total Requests" value={stats.total} helper="Leave entries on file" icon={<ClipboardCheck className="h-5 w-5" />} />
        <MetricPanel title="Pending" value={stats.pending} helper="Waiting for review" tone="orange" icon={<CalendarClock className="h-5 w-5" />} />
        <MetricPanel title="Approved" value={stats.approved} helper="Cleared requests" tone="green" icon={<ClipboardCheck className="h-5 w-5" />} />
      </div>

      <PanelShell title="Leave History" description="Review submitted outpass records and remove a request while it is still pending.">
        {loading ? (
          <div className="flex justify-center py-16"><Spinner size="lg" className="text-brand-primary" /></div>
        ) : leaves.length === 0 ? (
          <EmptyState title="No leave requests yet" description="Your submitted outpass requests will appear here." icon={<CalendarClock className="h-10 w-10" />} />
        ) : (
          <div className="space-y-4">
            {leaves.map(leave => {
              const days = Math.ceil((new Date(leave.to_date) - new Date(leave.from_date)) / (1000 * 60 * 60 * 24)) + 1;
              return (
                <div key={leave.id} className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-5">
                  <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
                    <div className="space-y-4">
                      <div className="flex flex-wrap items-center gap-3">
                        <div className="text-lg font-semibold text-brand-text">{days} day{days > 1 ? 's' : ''} leave</div>
                        <Badge variant={statusVariant(leave.status)}>{leave.status}</Badge>
                      </div>
                      <div className="grid gap-3 md:grid-cols-2">
                        <div className="rounded-[22px] border border-white bg-white px-4 py-3">
                          <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">From</div>
                          <div className="mt-2 text-sm font-semibold text-brand-text">{new Date(leave.from_date).toLocaleDateString()}</div>
                        </div>
                        <div className="rounded-[22px] border border-white bg-white px-4 py-3">
                          <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">To</div>
                          <div className="mt-2 text-sm font-semibold text-brand-text">{new Date(leave.to_date).toLocaleDateString()}</div>
                        </div>
                      </div>
                      <div className="rounded-[22px] border border-white bg-white px-4 py-3">
                        <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-brand-muted">Reason</div>
                        <div className="mt-2 text-sm leading-7 text-brand-text">{leave.reason}</div>
                      </div>
                    </div>

                    {leave.status === 'pending' ? (
                      <Button variant="outline" size="sm" onClick={() => handleDelete(leave.id)} className="h-11 rounded-[18px] px-4 text-red-600 border-red-200 hover:bg-red-50">
                        <Trash2 className="h-4 w-4" />
                        Delete
                      </Button>
                    ) : null}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </PanelShell>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Apply for Outpass" size="lg">
        <form onSubmit={handleCreate} className="grid gap-5">
          <div className="grid gap-4 md:grid-cols-2">
            <Input type="date" label="From Date" required value={formData.from_date} onChange={event => setFormData(current => ({ ...current, from_date: event.target.value }))} className="h-14 rounded-[20px] bg-[#fbfbff] px-5" />
            <Input type="date" label="To Date" required value={formData.to_date} onChange={event => setFormData(current => ({ ...current, to_date: event.target.value }))} className="h-14 rounded-[20px] bg-[#fbfbff] px-5" />
          </div>
          <Textarea
            label="Reason for Leave"
            required
            value={formData.reason}
            onChange={event => setFormData(current => ({ ...current, reason: event.target.value }))}
            placeholder="Share the purpose of your leave request."
            className="min-h-[140px] rounded-[20px] bg-[#fbfbff] px-5 py-4"
          />
          <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
            <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="h-12 rounded-[18px] px-5">Cancel</Button>
            <Button type="submit" loading={submitLoading} className="h-12 rounded-[18px] px-5">{submitLoading ? 'Submitting...' : 'Submit Request'}</Button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { myRoomAPI } from '../../services/api';
import { BedDouble, Calendar, Building2, AlertCircle } from 'lucide-react';
import { Spinner } from '../../components/ui';

function InfoCard({ label, value, accent = false }) {
  return (
    <div className={`rounded-xl p-4 ${accent ? 'bg-brand-primary/5 border border-brand-primary/20' : 'bg-gray-50 border border-brand-border/50'}`}>
      <p className={`text-xs font-semibold uppercase tracking-wider mb-1 ${accent ? 'text-brand-primary' : 'text-brand-muted'}`}>{label}</p>
      <p className={`text-sm font-bold ${accent ? 'text-brand-primary' : 'text-gray-900'}`}>{value || 'N/A'}</p>
    </div>
  );
}

export default function StudentMyRoomPage() {
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState('');

  useEffect(() => {
    myRoomAPI.get()
      .then(res => setData(res.data))
      .catch(() => setError('Failed to load room details. Please try again.'))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div className="flex items-center justify-center h-60">
      <Spinner size="lg" className="text-brand-primary" />
    </div>
  );

  if (error) return (
    <div className="flex items-center gap-3 bg-red-50 border border-red-200 rounded-2xl px-5 py-4 text-red-700">
      <AlertCircle className="h-5 w-5 flex-shrink-0" />
      <p className="text-sm">{error}</p>
    </div>
