  const { room, allocation } = data;
  const amenities = room.amenities ? room.amenities.split(',').map(a => a.trim()).filter(Boolean) : [];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900">My Room</h1>
        <p className="text-sm text-brand-muted mt-0.5">Your allocated room details</p>
      </div>

      {/* Room Banner */}
      <div className="relative overflow-hidden rounded-2xl bg-gradient-to-br from-brand-primary to-brand-primary/70 p-6 text-white shadow-lg">
        <div className="flex items-start justify-between">
          <div>
            <p className="text-sm text-white/70 font-medium">Room Number</p>
            <h2 className="text-4xl font-black tracking-tight mt-0.5">{room.roomNumber}</h2>
            <p className="text-white/80 text-sm mt-2">
              Block {room.blockName} &nbsp;·&nbsp; Floor {room.floorNumber}
            </p>
          </div>
          <div className="text-right">
            <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold ${
              allocation?.status === 'ACTIVE' ? 'bg-green-400/30 text-green-100 border border-green-400/40' : 'bg-yellow-400/30 text-yellow-100'
            }`}>
              {allocation?.status || 'ACTIVE'}
            </span>
            <BedDouble className="h-12 w-12 opacity-20 mt-3 ml-auto" />
          </div>
        </div>
      </div>

      <div className="grid md:grid-cols-2 gap-5">
        {/* Room Details */}
        <div className="bg-white rounded-2xl border border-brand-border/60 shadow-sm p-5">
          <h3 className="flex items-center gap-2 text-sm font-bold text-gray-900 mb-4">
            <BedDouble className="h-4 w-4 text-brand-primary" />
            Room Information
          </h3>
          <div className="grid grid-cols-2 gap-3">
            <InfoCard label="Room Type"    value={room.roomType} />
            <InfoCard label="Block"        value={`Block ${room.blockName}`} />
            <InfoCard label="Floor"        value={`Floor ${room.floorNumber}`} />
            <InfoCard label="Status"       value={room.status} />
          </div>
          {room.description && (
            <div className="mt-3 rounded-xl bg-gray-50 border border-brand-border/50 p-4">
              <p className="text-xs font-semibold uppercase tracking-wider text-brand-muted mb-1">Description</p>
              <p className="text-sm text-gray-700">{room.description}</p>
            </div>
          )}
        </div>

        {/* Allocation Details */}
        <div className="bg-white rounded-2xl border border-brand-border/60 shadow-sm p-5">
          <h3 className="flex items-center gap-2 text-sm font-bold text-gray-900 mb-4">
            <Calendar className="h-4 w-4 text-brand-primary" />
            Allocation Details
          </h3>
          <div className="grid grid-cols-2 gap-3">
            <InfoCard label="Academic Year" value={allocation?.academicYear}  accent />
            <InfoCard label="Semester"      value={allocation?.semester}      accent />
            <InfoCard
              label="Allocated On"
              value={allocation?.allocationDate ? new Date(allocation.allocationDate).toLocaleDateString('en-IN') : null}
            />
            <InfoCard
              label="End Date"
              value={allocation?.endDate ? new Date(allocation.endDate).toLocaleDateString('en-IN') : 'Ongoing'}
            />
          </div>
        </div>
      </div>

      {/* Amenities */}
      {amenities.length > 0 && (
        <div className="bg-white rounded-2xl border border-brand-border/60 shadow-sm p-5">
          <h3 className="flex items-center gap-2 text-sm font-bold text-gray-900 mb-3">
            <Building2 className="h-4 w-4 text-brand-primary" />
            Amenities
          </h3>
          <div className="flex flex-wrap gap-2">
            {amenities.map((a, i) => (
              <span key={i} className="bg-brand-primary/10 text-brand-primary text-xs font-semibold px-3 py-1 rounded-full">
                {a}
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { noticesAPI } from '../../services/api';
import { Badge, Spinner, EmptyState, PageHeader, SectionCard } from '../../components/ui';
import { format } from 'date-fns';

const CAT_BADGE = { general: 'default', urgent: 'danger', maintenance: 'warning', accounts: 'info', events: 'primary' };

export default function StudentNotices() {
  const [notices, setNotices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    setLoading(true);
    noticesAPI.getAll({ category: filter || undefined })
      .then(r => setNotices(r.data.data))
      .finally(() => setLoading(false));
  }, [filter]);

  return (
    <div className="space-y-5 animate-fade-in">
      <PageHeader
        eyebrow="Communication Centre"
        title="Student Notices"
        description="Browse published hostel announcements, student-specific updates, and administrative circulars."
      />

      <SectionCard title="Notice Filters" description="Filter published communication by category.">
        <div className="flex gap-2 flex-wrap">
          {['', 'general', 'urgent', 'maintenance', 'accounts', 'events'].map(category => (
            <button
              key={category}
              onClick={() => setFilter(category)}
              className={`px-4 py-2 rounded-full text-xs font-semibold transition-all
                ${filter === category
                  ? 'bg-brand-primary text-white shadow-brand'
                  : 'bg-white text-brand-muted border border-brand-border hover:border-brand-primary/30'}`}
            >
              {category ? category.charAt(0).toUpperCase() + category.slice(1) : 'All'}
            </button>
          ))}
        </div>
      </SectionCard>

      {loading ? (
        <div className="flex justify-center py-16"><Spinner size="lg" className="text-brand-primary" /></div>
      ) : notices.length === 0 ? (
        <EmptyState title="No notices" description="There are no notices to display." />
      ) : (
        <div className="space-y-3">
          {notices.map((notice, i) => (
            <motion.div
              key={notice.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.04 }}
              className="bg-white rounded-2xl border border-gray-100 shadow-card p-5 hover:shadow-card-hover transition-shadow"
            >
              <div className="flex items-start gap-4">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-semibold flex-shrink-0
                  ${notice.category === 'urgent' ? 'bg-red-50 text-red-700' : notice.category === 'maintenance' ? 'bg-amber-50 text-amber-700' : notice.category === 'events' ? 'bg-purple-50 text-purple-700' : notice.category === 'accounts' ? 'bg-blue-50 text-blue-700' : 'bg-gray-50 text-gray-700'}`}>
                  {notice.category.slice(0, 3).toUpperCase()}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap mb-1">
                    <span className="font-semibold text-brand-text">{notice.title}</span>
                    <Badge variant={CAT_BADGE[notice.category] || 'default'}>{notice.category}</Badge>
                    {notice.target !== 'all' && <Badge variant="purple">{notice.target.replace('_', ' ')}</Badge>}
                  </div>
                  {notice.content && <p className="text-sm text-brand-muted mt-1 leading-relaxed">{notice.content}</p>}
                  <div className="flex items-center gap-3 text-xs text-gray-400 mt-3">
                    <span>{format(new Date(notice.created_at), 'dd MMM yyyy, HH:mm')}</span>
                    {notice.posted_by_name && <span>{notice.posted_by_name}</span>}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Megaphone } from 'lucide-react';
import { format } from 'date-fns';
import { noticesAPI } from '../../services/api';
import { Badge, EmptyState, PanelShell, PortalHero, Spinner } from '../../components/ui';

const CAT_BADGE = { general: 'default', urgent: 'danger', maintenance: 'warning', accounts: 'info', events: 'primary' };

export default function StudentNoticesPortal() {
  const [notices, setNotices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    setLoading(true);
    noticesAPI.getAll({ category: filter || undefined })
      .then(response => setNotices(response.data.data || []))
      .catch(() => setNotices([]))
      .finally(() => setLoading(false));
  }, [filter]);

  return (
    <div className="space-y-6">
      <PortalHero
        eyebrow="Communication Centre"
        title="Student Notices"
        description="Published announcements, urgent updates, and hostel communication arranged in a cleaner student-facing reading experience."
        accent="primary"
        icon={<Megaphone className="h-4 w-4" />}
      />

      <PanelShell title="Categories" description="Filter notices by announcement type.">
        <div className="flex flex-wrap gap-3">
          {['', 'general', 'urgent', 'maintenance', 'accounts', 'events'].map(category => (
            <button
              key={category || 'all'}
              type="button"
              onClick={() => setFilter(category)}
              className={`rounded-full border px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] transition-all ${
                filter === category
                  ? 'border-brand-primary bg-brand-primary text-white shadow-brand'
                  : 'border-brand-border bg-white text-brand-muted hover:border-brand-primary/30'
              }`}
            >
              {category || 'All'}
            </button>
          ))}
        </div>
      </PanelShell>

      <PanelShell title="Published Notices" description="Latest notice board entries for hostel residents.">
        {loading ? (
          <div className="flex justify-center py-16"><Spinner size="lg" className="text-brand-primary" /></div>
        ) : notices.length === 0 ? (
          <EmptyState title="No notices found" description="There are no published announcements for this category right now." icon={<Megaphone className="h-10 w-10" />} />
        ) : (
          <div className="space-y-4">
            {notices.map((notice, index) => (
              <motion.article
                key={notice.id}
                initial={{ opacity: 0, y: 14 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.04 }}
                className="rounded-[28px] border border-brand-border/70 bg-[#fafbff] p-5"
              >
                <div className="flex flex-col gap-4 sm:flex-row sm:items-start">
                  <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-brand-primary/10 text-brand-primary">
                    <Megaphone className="h-5 w-5" />
                  </div>
                  <div className="min-w-0 flex-1">
                    <div className="flex flex-wrap items-center gap-2">
                      <h3 className="text-lg font-semibold text-brand-text">{notice.title}</h3>
                      <Badge variant={CAT_BADGE[notice.category] || 'default'}>{notice.category}</Badge>
                      {notice.target !== 'all' ? <Badge variant="purple">{notice.target.replace('_', ' ')}</Badge> : null}
                    </div>
                    {notice.content ? <p className="mt-3 text-sm leading-7 text-brand-muted">{notice.content}</p> : null}
                    <div className="mt-4 text-xs font-medium uppercase tracking-[0.14em] text-brand-muted">
                      {format(new Date(notice.created_at), 'dd MMM yyyy, HH:mm')}
                      {notice.posted_by_name ? ` • ${notice.posted_by_name}` : ''}
                    </div>
                  </div>
                </div>
              </motion.article>
            ))}
          </div>
        )}
      </PanelShell>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { studentPortalAPI } from '../../services/api';
import { Spinner } from '../../components/ui';
import { AlertCircle, Mail, Phone, MapPin, Building2, BookOpen, Calendar, CheckCircle2, BedDouble, ShieldCheck } from 'lucide-react';

export default function StudentProfile() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    studentPortalAPI.getProfile()
      .then(r => setProfile(r.data.data))
      .catch(err => setError(err.response?.data?.message || 'Failed to load profile.'))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Spinner size="lg" className="text-brand-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-[60vh] p-4">
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="max-w-md w-full bg-white rounded-2xl shadow-card p-6 text-center border border-gray-100"
        >
          <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-red-500" />
          </div>
          <h2 className="text-xl font-bold text-gray-900 mb-2">Profile Not Linked</h2>
          <p className="text-sm text-gray-500 mb-6">{error}</p>
          <div className="bg-blue-50/50 rounded-xl p-4 text-left border border-blue-100">
            <p className="text-sm font-semibold text-blue-900 mb-1">How to fix this:</p>
            <p className="text-sm text-blue-700">Contact the hostel warden or administrator to link your registered email address to your student record.</p>
          </div>
        </motion.div>
      </div>
    );
  }

  const parseRoomStatus = () => {
    if (!profile.room_number) return { color: 'text-amber-500', bg: 'bg-amber-50', border: 'border-amber-200', text: 'Pending Allocation' };
    return { color: 'text-emerald-500', bg: 'bg-emerald-50', border: 'border-emerald-200', text: 'Assigned' };
  };

  const roomState = parseRoomStatus();

  return (
    <div className="pb-12 min-h-screen pt-8">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="flex flex-col gap-6">

          {/* Header Card */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            className="bg-white rounded-[2rem] p-6 sm:p-8 shadow-sm border border-gray-100 flex flex-col md:flex-row gap-6 md:gap-8 items-center md:items-start text-center md:text-left"
          >
            <motion.div
              initial={{ scale: 0.8 }}
              animate={{ scale: 1 }}
              transition={{ delay: 0.2, type: 'spring', stiffness: 150 }}
              className="w-24 h-24 sm:w-28 sm:h-28 rounded-[2rem] flex items-center justify-center text-white font-bold text-4xl shadow-md flex-shrink-0 bg-gradient-to-br from-brand-primary to-[#7e57c2]"
            >
              {profile.name.charAt(0).toUpperCase()}
            </motion.div>

            <div className="flex-1 pt-2">
              <div className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-brand-primary/10 text-brand-primary text-[10px] font-bold tracking-widest uppercase mb-3">
                <ShieldCheck className="w-3.5 h-3.5" />
                Verified Student
              </div>
              <h1 className="text-2xl sm:text-3xl font-black text-gray-900 tracking-tight mb-2 uppercase">
                {profile.name}
              </h1>
              <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-xs font-bold text-gray-400 uppercase tracking-widest">
                <div className="flex items-center gap-1.5">
                  <BookOpen className="w-4 h-4 text-gray-300" /> {profile.register_no}
                </div>
                <div className="hidden sm:block text-gray-200">•</div>
                <div className="flex items-center gap-1.5">
                  <Building2 className="w-4 h-4 text-gray-300" /> {profile.department}
                </div>
              </div>
            </div>

            <div className="md:self-end pt-4 md:pt-0">
